
import React, { useRef, useEffect } from 'react';
import './RichTextEditor.css';
import { FaBold, FaItalic, FaListUl, FaListOl, FaLink, FaUnlink, FaHeading, FaImage } from 'react-icons/fa';
import ImageUploadModal from '../modals/ImageUploadModal';

interface RichTextEditorProps {
    value: string;
    onChange: (value: string) => void;
    placeholder?: string;
    minHeight?: string;
}

const RichTextEditor: React.FC<RichTextEditorProps> = ({ value, onChange, placeholder, minHeight = '200px' }) => {
    const editorRef = useRef<HTMLDivElement>(null);
    const [isImageModalOpen, setIsImageModalOpen] = React.useState(false);
    const [editingImage, setEditingImage] = React.useState<HTMLImageElement | null>(null);

    useEffect(() => {
        if (editorRef.current && editorRef.current.innerHTML !== value) {
            editorRef.current.innerHTML = value || '';
        }
    }, [value]);

    const execCommand = (command: string, value: string = '') => {
        document.execCommand(command, false, value);
        if (editorRef.current) {
            onChange(editorRef.current.innerHTML);
        }
    };

    const handleInput = () => {
        if (editorRef.current) {
            onChange(editorRef.current.innerHTML);
        }
    };

    const addLink = () => {
        const url = prompt('Enter the URL:');
        if (url) {
            execCommand('createLink', url);
        }
    };

    const handleImageInsert = (url: string) => {
        if (editingImage) {
            // Updating existing image
            editingImage.src = url;
            setEditingImage(null);
        } else {
            // Inserting new image
            if (editorRef.current) {
                editorRef.current.focus();
                // We use a temporary dummy image to handle selection if needed, 
                // but simple insertHTML is usually better for predictable placement
                const imgHtml = `<img src="${url}" alt="Image" />`;
                document.execCommand('insertHTML', false, imgHtml);
            }
        }
        setIsImageModalOpen(false);
        if (editorRef.current) {
            onChange(editorRef.current.innerHTML);
        }
    };

    const handleContentClick = (e: React.MouseEvent) => {
        const target = e.target as HTMLElement;
        if (target.tagName === 'IMG') {
            setEditingImage(target as HTMLImageElement);
            setIsImageModalOpen(true);
        }
    };

    return (
        <div className="rich-text-editor-container">
            <div className="rte-toolbar">
                <button type="button" onClick={() => execCommand('bold')} title="Bold"><FaBold /></button>
                <button type="button" onClick={() => execCommand('italic')} title="Italic"><FaItalic /></button>
                <div className="rte-divider" />
                <button type="button" onClick={() => execCommand('formatBlock', 'h2')} title="Heading 2"><FaHeading /> 2</button>
                <button type="button" onClick={() => execCommand('formatBlock', 'h3')} title="Heading 3"><FaHeading /> 3</button>
                <button type="button" onClick={() => execCommand('formatBlock', 'p')} title="Paragraph">P</button>
                <div className="rte-divider" />
                <button type="button" onClick={() => execCommand('insertUnorderedList')} title="Bullet List"><FaListUl /></button>
                <button type="button" onClick={() => execCommand('insertOrderedList')} title="Numbered List"><FaListOl /></button>
                <div className="rte-divider" />
                <button type="button" onClick={addLink} title="Add Link"><FaLink /></button>
                <button type="button" onClick={() => execCommand('unlink')} title="Remove Link"><FaUnlink /></button>
                <div className="rte-divider" />
                <button type="button" onClick={() => { setEditingImage(null); setIsImageModalOpen(true); }} title="Insert Image"><FaImage /></button>
            </div>
            <div
                ref={editorRef}
                className="rte-content"
                contentEditable
                onInput={handleInput}
                onClick={handleContentClick}
                style={{ minHeight }}
                data-placeholder={placeholder}
            />

            <ImageUploadModal
                isOpen={isImageModalOpen}
                onClose={() => { setIsImageModalOpen(false); setEditingImage(null); }}
                onUpload={handleImageInsert}
                currentValue={editingImage ? editingImage.src : ''}
            />
        </div>
    );
};

export default RichTextEditor;
