/**
 * Mock Backend API for CMS
 * Mimics real API behavior with TypeScript types, logging, and artificial delays.
 */

// --- Types ---

export interface Submission {
    id: string;
    date: string;
    email: string;
    formName: string;
    message: string;
}

export interface Alert {
    id: string;
    user: string;
    action: string;
    timestamp: string;
    link: string | null;
    type: 'info' | 'success' | 'warning' | 'error';
}

export interface ApiResponse<T> {
    success: boolean;
    data?: T;
    error?: string;
}

// --- Constants & Persistence ---

const DELAY = 600; // ms

const STORAGE_KEYS = {
    ALERTS: 'sbu_cms_alerts',
    SUBMISSIONS: 'sbu_cms_submissions'
};

