// --- Helper Functions ---

const initializeStorage = () => {
    if (typeof window === 'undefined') return;
    if (!localStorage.getItem(STORAGE_KEYS.SUBMISSIONS)) {
        localStorage.setItem(STORAGE_KEYS.SUBMISSIONS, JSON.stringify(initialSubmissions));
    }
    if (!localStorage.getItem(STORAGE_KEYS.ALERTS)) {
        localStorage.setItem(STORAGE_KEYS.ALERTS, JSON.stringify(initialAlerts));
    }
};

const getFromStorage = <T>(key: string): T[] => {
    if (typeof window === 'undefined') return [];
    const data = localStorage.getItem(key);
    return data ? JSON.parse(data) : [];
};

// --- API Implementation ---

export const siteApi = {
    /**
     * Fetch all form submissions
     */
    async getSubmissions(): Promise<ApiResponse<Submission[]>> {
        return new Promise((resolve) => {
            console.log('[API] GET /submissions');
            setTimeout(() => {
                const data = getFromStorage<Submission>(STORAGE_KEYS.SUBMISSIONS);
                resolve({ success: true, data });
            }, DELAY);
        });
    },

    /**
     * Fetch all system alerts/activities
     */
    async getAlerts(): Promise<ApiResponse<Alert[]>> {
        return new Promise((resolve) => {
            console.log('[API] GET /alerts');
            setTimeout(() => {
                const data = getFromStorage<Alert>(STORAGE_KEYS.ALERTS);
                // Sort by timestamp newest first
                data.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
                resolve({ success: true, data });
            }, DELAY);
        });
    },

    /**
     * Mock function for future calls
     */
    async logActivity(user: string, action: string, link: string | null = null): Promise<ApiResponse<Alert>> {
        return new Promise((resolve) => {
            if (!user || !action) {
                console.warn('[API Warning] logActivity: Missing user or action', { user, action });
                return resolve({ success: false, error: 'Missing required parameters' });
            }

            console.log('[API] POST /alerts', { user, action, link });

            setTimeout(() => {
                const alerts = getFromStorage<Alert>(STORAGE_KEYS.ALERTS);
                const newAlert: Alert = {
                    id: `alt_${Date.now()}`,
                    user,
                    action,
                    timestamp: new Date().toISOString(),
                    link,
                    type: 'info'
                };

                alerts.unshift(newAlert);
                localStorage.setItem(STORAGE_KEYS.ALERTS, JSON.stringify(alerts));
                resolve({ success: true, data: newAlert });
            }, DELAY);
        });
    }
};

// Initialize on load
initializeStorage();
