import React, { useState, useEffect, useImperativeHandle, forwardRef } from 'react';
import './FormBuilderEditor.css';
import { useFormData } from '../../hooks/useFormData';
import { FormField, Form } from '../ppm/cms/form-builder/FormBuilderTypes';
import PopupDynamic from '../modals/PopupDynamic';
import { useCMS } from '../../contexts/CMSContext';
import SectionLockControl from './SectionLockControl';
import FormBuilderEditorSettings from './FormBuilderEditorSettings';
import { useEmailTemplates } from '../ppm/forms/useEmailTemplates';
import { getSupabase } from '../../database/supabase';
import { removeVietnameseTones } from '../../ppm/util/vietToLatin';
import { formatIdLatinKebab } from '../../ppm/util/formatIdLatinKebab';

const FIELD_TYPES = [
  { value: 'short_answer', label: 'Short Answer' },
  { value: 'paragraph', label: 'Paragraph' },
  { value: 'multiple_choice', label: 'Multiple Choice' },
  { value: 'dropdown', label: 'Dropdown' },
  { value: 'checkboxes', label: 'Checkboxes' },
  { value: 'email_address', label: 'Email' },
  { value: 'phone_number', label: 'Phone Number' },
  { value: 'date', label: 'Date' },
  { value: 'time', label: 'Time' },
];

const TEMPLATES = [
  { id: 'blank', label: 'Blank Form', fields: [] },
  {
    id: 'contact',
    label: 'Sample Contact Form',
    fields: [
      { id: 'f1', name: 'Email Address', type: 'short_answer', required: true, validation: { mode: 'email' } },
      { id: 'f2', name: 'Message', type: 'paragraph', required: false },
    ],
  },
];

type EditorTab = 'fields' | 'settings' | 'preview';

interface FormBuilderEditorProps {
  showNotification: (message: string, type?: 'success' | 'error' | 'info') => void;
}

const normalizeToken = (value: string) => {
  return value.trim().toLowerCase();
};

const FormBuilderEditor = forwardRef((props: FormBuilderEditorProps, ref) => {
  const { showNotification } = props;
  const [forms, setForms] = useState<Form[]>([]);
  const [loading, setLoading] = useState(true);

  const [activeFormId, setActiveFormId] = useState<string | null>(null);
  const [draftForm, setDraftForm] = useState<Form | null>(null);
  const [showTemplateMenu, setShowTemplateMenu] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [showEmailErrorPopup, setShowEmailErrorPopup] = useState(false);
  const [activeTab, setActiveTab] = useState<EditorTab>('fields');


  const [isSaving, setIsSaving] = useState(false);

  useImperativeHandle(ref, () => ({
    saveForm: handleSaveForm,
    deleteForm: () => {
      if (activeFormId) {
        setShowDeleteConfirm(true);
      } else {
        showNotification('Please select a form to delete', 'info');
      }
    },
    isSaving
  }));

  useEffect(() => {
    if (activeFormId) {
      const found = forms.find(f => f.id === activeFormId);
      if (found) {
        setDraftForm(JSON.parse(JSON.stringify(found)));
      } else {
        setActiveFormId(null);
        setDraftForm(null);
      }
    }
  }, [activeFormId, forms]);




  useEffect(() => {
    let mounted = true;



    const loadForms = async () => {
      try {
        setLoading(true);

        const supabase = await getSupabase();

        const { data, error } = await supabase
          .from("form_definitions")
          .select("*");

        if (error) throw error;

        if (!mounted) return;

        // 🔥 Transform DB → your Form type
        const parsedForms: Form[] = (data || []).map((row: any) => {
          const def = row.definition;
          const form = def?.form;

          return {
            id: form?.id || row.form_key,
            dbId: row.id, // 👈 Store the UUID
            title: form?.title || "Untitled",
            fields: (form?.fields || []).map((f: any, i: number) => ({
              id: f.id || `field_${i}`,
              name: f.name,
              type: f.type,
              required: f.required || false,
              placeholder: f.placeholder || "",
              helpText: f.helpText || "",
              options: f.options || undefined,
              mapping: f.mapping || undefined,
              validation: f.validation || undefined,
            })),

            // ✅ ADD THIS
            settings: def?.settings || {
              sendEmailOnSubmission: false,
            },
          };
        });

        setForms(parsedForms);

        // optional: auto-select first form
        if (parsedForms.length > 0 && !activeFormId) {
          setActiveFormId(parsedForms[0].id);
        }

      } catch (err) {
        console.error("Failed to load forms:", err);
      } finally {
        if (mounted) setLoading(false);
      }
    };

    loadForms();

    return () => {
      mounted = false;
    };
  }, []);



  // ✅ After
  const { templates: emailTemplates, loading: emailTemplatesLoading, saveTemplate } = useEmailTemplates();
  useEffect(() => {
    if (!emailTemplatesLoading) {
      console.log('EMAIL TEMPLATES (FROM HOOK):', emailTemplates);
    }
  }, [emailTemplates, emailTemplatesLoading]);



  const handleCreateForm = () => {
    console.log('🟡 CLICK: Create Form triggered');

    const timestamp = Date.now();
    const newDraft: Form = {
      id: `form_${timestamp}`,
      title: `New Form ${timestamp}`,
      fields: [],
      meta: { temp: { isNew: true } }
    };

    console.log('🆕 NEW DRAFT:', newDraft);

    // 👇 THIS IS WHAT YOU WERE MISSING
    setForms(prev => {
      const updated = [...prev, newDraft];
      console.log('📦 UPDATED FORMS LIST:', updated);
      return updated;
    });

    setActiveFormId(newDraft.id); // 👈 IMPORTANT so it highlights
    setDraftForm(newDraft);

    setShowTemplateMenu(false);
    setActiveTab('fields');
  };

  const handleLoadTemplate = (templateId: string) => {
    const template = TEMPLATES.find(t => t.id === templateId);
    if (templateId === 'blank') {
      handleCreateForm();
      return;
    }
    if (template) {
      const newDraft: Form = {
        id: `temp_${Date.now()}`,
        title: template.label,
        fields: JSON.parse(JSON.stringify(template.fields)),
      };
      setActiveFormId(null);
      setDraftForm(newDraft);
      setActiveTab('fields');
    }
    setShowTemplateMenu(false);
  };

  const { updateGhiDanhNhapHocContent } = useCMS();

  const transformFormData = (input: any) => {
    const result: any = {
      title: 'GHI DANH NHẬP HỌC',
      formId: input.id,
      form: {
        id: input.id,
        title: input.title,
        fields: input.fields.map((field: any) => {
          let format = 'text';
          if (field.id === 'field_3' || field.type === 'date') format = 'date';
          if (field.validation?.mode === 'email') format = 'email';
          if (field.id === 'field_6') format = 'phone';
          const baseField: any = {
            id: field.id,
            format,
            name: field.name,
            type: field.type,
            required: field.required || false,
            placeholder: field.placeholder || '',
          };
          if (field.mapping) baseField.mapping = field.mapping;
          if (field.options) baseField.options = field.options;
          if (field.helpText) baseField.helpText = field.helpText;
          if (field.validation) baseField.validation = field.validation;
          return baseField;
        }),
      },
      fields: {},
      submitLabel: 'GHI DANH NGAY',
    };

    input.fields.forEach((field: any) => {
      const legacyField: any = { label: field.name, placeholder: field.placeholder || '' };
      if (field.id === 'field_4' || field.type === 'multiple_choice') {
        legacyField.male = field.options?.[0] || 'Nam';
        legacyField.female = field.options?.[1] || 'Nữ';
      }
      if (field.type === 'dropdown' || field.type === 'checkboxes') {
        legacyField.options = field.options?.map((opt: string) => ({ label: opt })) || [];
      }
      result.fields[field.id] = legacyField;
    });

    return result;
  };


  const saveFormToDB = async (form: Form) => {
    const supabase = await getSupabase();


    const payload = {
      form: {
        id: form.id,
        title: form.title,
        fields: form.fields,
      },
    };

    const { error } = await supabase
      .from("form_definitions")
      .upsert({
        definition: payload,
      });

    if (error) throw error;
  };

  const deleteFormFromDB = async (formId: string) => {
    const supabase = await getSupabase();

    const { error } = await supabase
      .from("form_definitions")
      .delete()
      .eq("form_key", formId);

    if (error) throw error;
  };


  function hasFormKeyChanged(
    isNewForm: boolean,
    currentFormKey: string,
    newId: string
  ): boolean {
    if (isNewForm) return false;
    console.log(currentFormKey)
    console.log(newId)
    return currentFormKey !== newId;
  }


  const handleSaveForm = async () => {

    if (!draftForm) return;

    const emailOnSubmit = (draftForm as any).settings?.submit === 'email';
    const hasEmailField = draftForm.fields.some(f => f.type === 'email_address');
    
    if (emailOnSubmit && !hasEmailField) {
      setShowEmailErrorPopup(true);
      return;
    }

    try {
      setIsSaving(true);

      const supabase = await getSupabase();

      const settings = (draftForm as any).settings || {};

      const isNewForm: boolean = !!(draftForm?.meta?.temp?.isNew)
      console.log('is new', isNewForm)
      console.log(draftForm)

      // ── 1. Save form definition ─────────────────────────────────────────────




      let id: string = formatIdLatinKebab(draftForm.title)
      console.log(draftForm)

      let formKeyUpdated: boolean = hasFormKeyChanged(isNewForm, draftForm.id, id)
      console.log('updated key', `${formKeyUpdated}`)

      function applyFieldMappings(fields: any[], map: any) {
        const safeMap = map || {};

        return fields.map((field: any) => {
          let token = safeMap[field.id];

          // 🚑 fallback if token is missing or clearly wrong
          if (!token || token === '' || token === 'new question') {
            token = field.name.trim().toLowerCase();
          }

          return {
            ...field,
            mapping: token,
          };
        });
      }


      console.log(draftForm.fields)

      console.log(settings.emailTokenMap)
      console.log(settings)

      const variables = draftForm.fields.map((field: any) => ({
        key: field.mapping || field.name,
        desc: field.name,
      }));
      console.log(variables)


      const fieldsWithMappings: any = applyFieldMappings(draftForm.fields, settings.emailTokenMap)

      console.log(fieldsWithMappings)
      const payload: any = {
        definition: {
          form: {
            id: draftForm.id,
            title: draftForm.title,
            fields: fieldsWithMappings,
            submit: settings.submit ?? false,
          },
          settings: {
            submit: settings.submit ?? false,
            emailTemplateId: settings.emailTemplateId ?? null,
            emailTokenMap: settings.emailTokenMap ?? {},
            successMessage: settings.successMessage ?? '',
            emailSubject: settings.emailSubject ?? '',
            emailBody: settings.emailBody ?? '',
          }
        },
        form_id: draftForm.id, // 👈 Required column (slug)
        published: false       // 👈 Required column
      };

      // If we have a database UUID, include it to ensure we update the existing record
      if ((draftForm as any).dbId) {
        payload.id = (draftForm as any).dbId;
      }

      // 2. Save form definition
      let upsertData: any = null;
      try {
        const { data, error } = await supabase
          .from('form_definitions')
          .upsert(payload)
          .select();
        
        if (error) throw error;
        upsertData = data;
      } catch (fErr: any) {
        throw new Error(`Form Definition Error: ${fErr.message || fErr.details || 'Unable to update database'}`);
      }

      const savedForm = { ...draftForm };

      // Update the local state with the database UUID if it was newly created
      if (upsertData && upsertData[0]) {
        (savedForm as any).dbId = upsertData[0].id;
      }

      // remove the temp attribute that is used to track if form is new or existing
      if (savedForm?.meta?.temp) delete (savedForm as any).meta.temp

      // ── 2. Save email template ─────────────────────────────────────────────
      if (settings.submit === 'email') {
        try {
          // 🔍 find existing template by template_name (CONSISTENT KEY)
          const existingTemplate = emailTemplates.find(
            (t: any) => t.template_name === savedForm.id
          );

          // ✅ UPSERT LOGIC
          await saveTemplate({
            id: existingTemplate?.id, // if exists → update, else → insert
            template_name: savedForm.id, // 👈 ALWAYS use same key
            subject: settings.emailSubject || '',
            body: settings.emailBody || '',
            variables,
          });
        } catch (tErr: any) {
          throw new Error(`Email Template Error: ${tErr.message || tErr.details || 'Unable to update email settings'}`);
        }
      }

      // ── 3. Update local UI state ────────────────────────────────────────────
      setForms(prev => {
        const exists = prev.find(f => f.id === savedForm.id);
        return exists
          ? prev.map(f => f.id === savedForm.id ? savedForm : f)
          : [...prev, savedForm];
      });

      setActiveFormId(savedForm.id);
      setDraftForm(savedForm)
      showNotification('Form saved successfully!', 'success');

    } catch (err: any) {
      console.error('Save failed:', err);
      // provide more details in the notification (MTC-BDPQ-UI-01)
      const errorMsg = err.message || err.details || 'Unknown error';
      showNotification(`Failed to save form: ${errorMsg}`, 'error');
    } finally {
      setIsSaving(false);
    }
  };


  const handleRenameForm = (newTitle: string) => {
    if (!draftForm) return;
    setDraftForm({ ...draftForm, title: newTitle });
  };


  const handleAddField = () => {
    if (!draftForm) return;

    const newField: FormField = {
      id: `field_${Date.now()}`,
      name: 'New Question',
      type: 'short_answer',
      required: false,
      helpText: '',
    };

    const existingMap = (draftForm as any).settings?.emailTokenMap || {};

    // 👇 generate default token for ONLY this field
    const base = newField.name.trim();
    let token = base;
    let i = 1;

    const existingTokens = Object.values(existingMap);

    while (existingTokens.includes(token)) {
      token = `${base}_${i++}`;
    }

    const updatedTokenMap = {
      ...existingMap,
      [newField.id]: normalizeToken(token),
    };

    const updatedForm = {
      ...draftForm,
      fields: [...draftForm.fields, newField],
      settings: {
        ...(draftForm as any).settings,
        emailTokenMap: updatedTokenMap,
      },
    };

    setDraftForm(updatedForm);

    setForms(prev =>
      prev.map(f => (f.id === updatedForm.id ? updatedForm : f))
    );

    console.log('➕ FIELD ADDED:', newField);
    console.log('🧠 TOKEN MAP UPDATED:', updatedTokenMap);
  };

  const handleUpdateField = (fieldId: string, updates: Partial<FormField>) => {
    if (!draftForm) return;

    const existingMap = (draftForm as any).settings?.emailTokenMap || {};
    const oldField = draftForm.fields.find(f => f.id === fieldId);
    if (!oldField) return;

    const updatedFields = draftForm.fields.map(f =>
      f.id === fieldId ? { ...f, ...updates } : f
    ) as FormField[];

    let updatedTokenMap = existingMap;

    // If the field name changed, only auto-update the token when the token
    // was still using the old default-generated value.
    if (
      updates.name !== undefined &&
      updates.name !== oldField.name
    ) {
      const oldBase = oldField.name.trim();
      const currentToken = existingMap[fieldId];

      // Build the next default token from the NEW name, avoiding collisions
      const newBase = updates.name.trim();
      let nextToken = newBase;
      let i = 1;

      const usedTokens = Object.entries(existingMap)
        .filter(([id]) => id !== fieldId)
        .map(([, token]) => token);

      while (usedTokens.includes(nextToken)) {
        nextToken = `${newBase}_${i++}`;
      }

      // Only replace token if it still matched the old auto/default value
      // or was empty/undefined.
      if (
        currentToken === undefined ||
        currentToken === '' ||
        currentToken === oldBase
      ) {
        updatedTokenMap = {
          ...existingMap,
          [fieldId]: nextToken,
        };
      }
    }

    setDraftForm({
      ...draftForm,
      fields: updatedFields,
      settings: {
        ...(draftForm as any).settings,
        emailTokenMap: updatedTokenMap,
      },
    });
  };

  const handleRemoveField = (fieldId: string) => {
    if (!draftForm) return;
    const updatedFields = draftForm.fields.filter(f => f.id !== fieldId);
    setDraftForm({ ...draftForm, fields: updatedFields });
  };

  const handleDeleteActiveForm = async () => {
    if (!activeFormId) return;

    try {
      const supabase = await getSupabase();

      const { error } = await supabase
        .from("form_definitions")
        .delete()
        .eq("form_key", activeFormId);

      if (error) throw error;

      setForms(prev => prev.filter(f => f.id !== activeFormId));
      setActiveFormId(null);
      setDraftForm(null);
      setShowDeleteConfirm(false);

    } catch (err) {
      console.error("Delete failed:", err);
    }
  };

  // ─── Tab label config ───────────────────────────────────────────────────────
  const TABS: { id: EditorTab; label: string }[] = [
    { id: 'fields', label: 'Fields' },
    { id: 'preview', label: 'Preview' },
    { id: 'settings', label: 'Settings' },

  ];

  // ─── Preview renderer ───────────────────────────────────────────────────────
  const renderPreviewField = (field: FormField) => {
    const isChoice = ['multiple_choice', 'dropdown', 'checkboxes'].includes(field.type);
    return (
      <div key={field.id} style={{ marginBottom: '1.25rem' }}>
        <label style={{ display: 'block', fontSize: '13px', fontWeight: 500, marginBottom: '0.375rem', color: '#374151' }}>
          {field.name}
          {field.required && <span style={{ color: '#ef4444', marginLeft: '2px' }}>*</span>}
        </label>
        {field.helpText && (
          <p style={{ fontSize: '12px', color: '#6b7280', marginBottom: '0.375rem', marginTop: 0 }}>{field.helpText}</p>
        )}
        {field.type === 'paragraph' ? (
          <textarea
            disabled
            placeholder={field.placeholder || ''}
            style={{ width: '100%', boxSizing: 'border-box', border: '1px solid #d1d5db', borderRadius: '6px', padding: '8px 10px', fontSize: '13px', minHeight: '80px', background: '#f9fafb', resize: 'vertical', color: '#9ca3af' }}
          />
        ) : field.type === 'dropdown' ? (
          <select
            disabled
            style={{ width: '100%', boxSizing: 'border-box', border: '1px solid #d1d5db', borderRadius: '6px', padding: '8px 10px', fontSize: '13px', background: '#f9fafb', color: '#9ca3af' }}
          >
            <option>{field.placeholder || 'Select an option'}</option>
            {((field as any).options || []).map((opt: string, i: number) => (
              <option key={i}>{opt}</option>
            ))}
          </select>
        ) : field.type === 'multiple_choice' ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.375rem' }}>
            {((field as any).options || []).map((opt: string, i: number) => (
              <label key={i} style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '13px', color: '#6b7280', cursor: 'default' }}>
                <input type="radio" disabled /> {opt}
              </label>
            ))}
          </div>
        ) : field.type === 'checkboxes' ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.375rem' }}>
            {((field as any).options || []).map((opt: string, i: number) => (
              <label key={i} style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '13px', color: '#6b7280', cursor: 'default' }}>
                <input type="checkbox" disabled /> {opt}
              </label>
            ))}
          </div>
        ) : (
          <input
            disabled
            type={field.type === 'email_address' ? 'email' : field.type === 'phone_number' ? 'tel' : field.type === 'date' ? 'date' : field.type === 'time' ? 'time' : 'text'}
            placeholder={field.placeholder || ''}
            style={{ width: '100%', boxSizing: 'border-box', border: '1px solid #d1d5db', borderRadius: '6px', padding: '8px 10px', fontSize: '13px', background: '#f9fafb', color: '#9ca3af' }}
          />
        )}
      </div>
    );
  };

  if (loading) {
    return (
      <div className="form-builder-container">
        <div className="workspace-empty-state">
          <p>Loading forms...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="form-builder-container">
      {/* ── Sidebar ─────────────────────────────────────────────────────────── */}
      <aside className="form-builder-sidebar">
        <div className="sidebar-header">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
            <h3 style={{ margin: 0 }}>My Forms</h3>
            <div style={{ position: 'relative' }}>
              <button
                className="btn-secondary"
                style={{ padding: '4px 8px', fontSize: '12px', cursor: 'pointer', background: '#f3f4f6', border: '1px solid #d1d5db', borderRadius: '4px' }}
                onClick={() => setShowTemplateMenu(!showTemplateMenu)}
              >
                Templates ▾
              </button>
              {showTemplateMenu && (
                <div style={{ position: 'absolute', top: '100%', right: 0, background: 'white', border: '1px solid #e5e7eb', borderRadius: '6px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)', zIndex: 10, width: '180px', padding: '4px' }}>
                  {TEMPLATES.map(t => (
                    <button
                      key={t.id}
                      style={{ width: '100%', textAlign: 'left', padding: '8px', background: 'none', border: 'none', fontSize: '13px', cursor: 'pointer', borderRadius: '4px' }}
                      onMouseOver={e => (e.currentTarget.style.background = '#f3f4f6')}
                      onMouseOut={e => (e.currentTarget.style.background = 'none')}
                      onClick={() => handleLoadTemplate(t.id)}
                    >
                      {t.label}
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
          <button className="btn-create-form" onClick={handleCreateForm}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <line x1="12" y1="5" x2="12" y2="19" />
              <line x1="5" y1="12" x2="19" y2="12" />
            </svg>
            Create Form
          </button>
        </div>

        <div className="form-list">
          {forms.map(form => (
            <div
              key={form.id}
              className={`form-list-item ${activeFormId === form.id ? 'active' : ''}`}
              onClick={() => { setActiveFormId(form.id); setActiveTab('fields'); }}
            >
              <span className="form-item-title">{form.title}</span>
              <div className="form-item-badge">{form.fields.length} fields</div>
            </div>
          ))}
          {forms.length === 0 && (
            <p style={{ textAlign: 'center', color: '#9ca3af', fontSize: '0.875rem', marginTop: '2rem' }}>
              No forms created yet.
            </p>
          )}
        </div>
      </aside>

      {/* ── Main Workspace ───────────────────────────────────────────────────── */}
      <main className="form-builder-workspace">
        {draftForm ? (
          <div style={{ width: '100%', maxWidth: '800px' }}>
            {/* Info Box (MTC-BDPQ-81) */}
            <div className="form-builder-info-box">
              <div className="info-icon">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <circle cx="12" cy="12" r="10"></circle>
                  <line x1="12" y1="16" x2="12" y2="12"></line>
                  <line x1="12" y1="8" x2="12.01" y2="8"></line>
                </svg>
              </div>
              <div className="info-content">
                <p><strong>Note:</strong> You can design and build your forms here. Once finished, navigate to the specific page where you want to display the form to select and activate it.</p>
              </div>
            </div>

            <div className="form-editor-card">

              {/* ── Header row (title + save/delete) ── */}
              <div className="form-editor-header">
                <input
                  className="form-title-input"
                  value={draftForm.title}
                  onChange={e => handleRenameForm(e.target.value)}
                  placeholder="Enter form title..."
                  disabled={!!draftForm.locked}
                />
                <div style={{ marginRight: '1rem' }}>
                  <SectionLockControl
                    locked={draftForm.locked}
                    onToggle={locked => setDraftForm({ ...draftForm, locked })}
                  />
                </div>
                <div className="form-actions" style={{ display: 'flex', alignItems: 'center' }}>
                  <button
                    onClick={handleSaveForm}
                    disabled={isSaving}
                    style={{
                      background: '#10b981',
                      color: 'white',
                      border: 'none',
                      padding: '8px 16px',
                      borderRadius: '6px',
                      fontWeight: 500,
                      fontSize: '14px',
                      cursor: isSaving ? 'not-allowed' : 'pointer',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '6px',
                      marginRight: '8px',
                      boxShadow: '0 1px 2px rgba(0,0,0,0.05)',
                      opacity: isSaving ? 0.7 : 1
                    }}
                    onMouseOver={e => !isSaving && (e.currentTarget.style.background = '#059669')}
                    onMouseOut={e => !isSaving && (e.currentTarget.style.background = '#10b981')}
                  >
                    {isSaving ? (
                      <>
                        <div style={{
                          width: '14px',
                          height: '14px',
                          border: '2px solid white',
                          borderTop: '2px solid transparent',
                          borderRadius: '50%',
                          animation: 'spin 0.8s linear infinite'
                        }} />
                        Saving...
                      </>
                    ) : (
                      <>
                        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                          <path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z" />
                          <polyline points="17 21 17 13 7 13 7 21" />
                          <polyline points="7 3 7 8 15 8" />
                        </svg>
                        Save Form
                      </>
                    )}
                  </button>
                  {activeFormId && (
                    <button className="btn-delete-form" onClick={() => setShowDeleteConfirm(true)}>
                      Delete Form
                    </button>
                  )}
                </div>
              </div>

              {/* ── TAB BAR ── */}
              <div style={{ display: 'flex', borderBottom: '1px solid #e5e7eb', background: '#f9fafb', padding: '0 1.25rem' }}>
                {TABS.map(tab => (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    style={{
                      background: 'none',
                      border: 'none',
                      borderBottom: activeTab === tab.id ? '2px solid #6366f1' : '2px solid transparent',
                      padding: '10px 16px',
                      fontSize: '13px',
                      fontWeight: 500,
                      color: activeTab === tab.id ? '#111827' : '#6b7280',
                      cursor: 'pointer',
                      marginBottom: '-1px',
                      transition: 'color 0.15s, border-color 0.15s',
                    }}
                    onMouseOver={e => { if (activeTab !== tab.id) e.currentTarget.style.color = '#374151'; }}
                    onMouseOut={e => { if (activeTab !== tab.id) e.currentTarget.style.color = '#6b7280'; }}
                  >
                    {tab.label}
                  </button>
                ))}
              </div>

              {/* ── TAB: Fields ── */}
              {activeTab === 'fields' && (
                <div
                  className="fields-container"
                  style={{ opacity: draftForm.locked ? 0.6 : 1, pointerEvents: draftForm.locked ? 'none' : 'auto', transition: 'opacity 0.3s' }}
                >
                  {draftForm.fields.length === 0 && (
                    <div style={{ textAlign: 'center', padding: '3rem 1rem', color: '#6b7280' }}>
                      <p style={{ fontSize: '1.125rem', fontWeight: 500 }}>Empty Form</p>
                      <p style={{ fontSize: '0.875rem' }}>Click "Add Field" below to begin building your form.</p>
                    </div>
                  )}

                  {draftForm.fields.map(field => (
                    <div key={field.id} className="field-block">
                      <div className="field-row">
                        <div className="field-input-group">
                          <label className="field-label">Question name</label>
                          <input
                            className="input-standard"
                            value={field.name}
                            onChange={e => handleUpdateField(field.id, { name: e.target.value })}
                            placeholder="e.g. Email Address"
                          />
                        </div>
                        <div className="field-input-group">
                          <label className="field-label">Field Type</label>
                          <select
                            className="input-standard"
                            value={field.type}
                            onChange={e => {
                              const newType = e.target.value as any;
                              const updates: any = { type: newType };
                              if (['multiple_choice', 'dropdown', 'checkboxes'].includes(newType) && !(field as any).options) {
                                updates.options = ['Option 1'];
                              }
                              handleUpdateField(field.id, updates);
                            }}
                          >
                            {FIELD_TYPES.map(type => (
                              <option key={type.value} value={type.value}>{type.label}</option>
                            ))}
                          </select>
                        </div>
                        <button className="btn-delete-field" onClick={() => handleRemoveField(field.id)} title="Remove field">
                          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <polyline points="3 6 5 6 21 6" />
                            <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2" />
                          </svg>
                        </button>
                      </div>

                      {['linear_scale', 'file_upload'].includes(field.type) && (
                        <div style={{ marginTop: '1rem', padding: '0.75rem', background: '#f8f9fa', borderRadius: '6px', fontSize: '13px', color: '#6b7280', border: '1px dashed #d1d5db' }}>
                          {field.type === 'linear_scale' ? 'Linear scale field (configure later)' : 'File upload field (configure later)'}
                        </div>
                      )}

                      {['multiple_choice', 'dropdown', 'checkboxes'].includes(field.type) && (
                        <div className="field-options-editor" style={{ marginTop: '1.25rem', paddingLeft: '1rem', borderLeft: '3px solid #e5e7eb' }}>
                          <label className="field-label" style={{ marginBottom: '0.75rem', display: 'block' }}>Options</label>
                          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                            {((field as any).options || []).map((option: string, idx: number) => (
                              <div key={idx} style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
                                <div style={{ color: '#9ca3af', fontSize: '12px' }}>{idx + 1}.</div>
                                <input
                                  className="input-standard"
                                  style={{ padding: '6px 10px', height: '36px' }}
                                  value={option}
                                  onChange={e => {
                                    const newOpts = [...(field as any).options];
                                    newOpts[idx] = e.target.value;
                                    handleUpdateField(field.id, { options: newOpts });
                                  }}
                                  placeholder={`Option ${idx + 1}`}
                                />
                                <button
                                  onClick={() => {
                                    const newOpts = (field as any).options.filter((_: any, i: number) => i !== idx);
                                    handleUpdateField(field.id, { options: newOpts });
                                  }}
                                  style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', padding: '4px' }}
                                >
                                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                    <line x1="18" y1="6" x2="6" y2="18" />
                                    <line x1="6" y1="6" x2="18" y2="18" />
                                  </svg>
                                </button>
                              </div>
                            ))}
                            <button
                              onClick={() => {
                                const currentOpts = (field as any).options || [];
                                handleUpdateField(field.id, { options: [...currentOpts, `Option ${currentOpts.length + 1}`] });
                              }}
                              style={{ alignSelf: 'flex-start', background: 'none', border: 'none', color: '#3b82f6', fontSize: '13px', fontWeight: 500, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '4px', padding: '4px 8px', marginTop: '4px' }}
                            >
                              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                <line x1="12" y1="5" x2="12" y2="19" />
                                <line x1="5" y1="12" x2="19" y2="12" />
                              </svg>
                              Add Option
                            </button>
                          </div>
                        </div>
                      )}

                      <div className="field-footer-row" style={{ marginTop: '1.25rem' }}>
                        <div className="field-input-group" style={{ flex: 1 }}>
                          <label className="field-label">Placeholder (Optional)</label>
                          <input
                            className="input-standard"
                            value={field.placeholder || ''}
                            onChange={e => handleUpdateField(field.id, { placeholder: e.target.value })}
                            placeholder="Gray text inside input..."
                          />
                        </div>
                        <div className="field-input-group" style={{ flex: 1 }}>
                          <label className="field-label">Help Text</label>
                          <input
                            className="input-standard input-help-text"
                            value={field.helpText || ''}
                            onChange={e => handleUpdateField(field.id, { helpText: e.target.value })}
                            placeholder="Instruction for users..."
                          />
                        </div>
                        <label className="field-required-label">
                          <input
                            type="checkbox"
                            checked={!!field.required}
                            onChange={e => handleUpdateField(field.id, { required: e.target.checked })}
                          />
                          <span>Required</span>
                        </label>
                      </div>
                    </div>
                  ))}

                  <div className="add-field-footer">
                    <button className="btn-add-field" onClick={handleAddField}>
                      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                        <line x1="12" y1="5" x2="12" y2="19" />
                        <line x1="5" y1="12" x2="19" y2="12" />
                      </svg>
                      Add Field
                    </button>
                  </div>
                </div>
              )}

              {/* ── TAB: Settings ── */}
              {activeTab === 'settings' && (
                <FormBuilderEditorSettings draftForm={draftForm} setDraftForm={setDraftForm} />
              )}

              {/* ── TAB: Preview ── */}
              {activeTab === 'preview' && (
                <div style={{ padding: '1.5rem' }}>
                  {draftForm.fields.length === 0 ? (
                    <div style={{ textAlign: 'center', padding: '3rem 1rem', color: '#6b7280' }}>
                      <p style={{ fontSize: '1.125rem', fontWeight: 500 }}>No fields to preview</p>
                      <p style={{ fontSize: '0.875rem' }}>Add some fields in the Fields tab first.</p>
                    </div>
                  ) : (
                    <div style={{ border: '1px solid #e5e7eb', borderRadius: '10px', padding: '1.75rem', background: '#fff' }}>
                      {draftForm.fields.map(field => renderPreviewField(field))}
                      <button
                        disabled
                        style={{ marginTop: '0.5rem', width: '100%', background: '#6366f1', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '6px', fontSize: '14px', fontWeight: 500, cursor: 'not-allowed', opacity: 0.85 }}
                      >
                        {(draftForm as any).submitLabel || 'GHI DANH NGAY'}
                      </button>
                    </div>
                  )}
                </div>
              )}

            </div>
          </div>
        ) : (
          <div className="workspace-empty-state">
            <svg width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round" opacity="0.3" style={{ marginBottom: '1.5rem' }}>
              <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" />
              <polyline points="14 2 14 8 20 8" />
              <line x1="9" y1="15" x2="15" y2="15" />
              <line x1="9" y1="11" x2="15" y2="11" />
              <line x1="9" y1="19" x2="12" y2="19" />
            </svg>
            <h2>Form Builder</h2>
            <p>Select an existing form from the sidebar or click "Create Form" to get started.</p>
          </div>
        )}
      </main>

      <PopupDynamic
        isOpen={showDeleteConfirm}
        onClose={() => setShowDeleteConfirm(false)}
        title="Delete Form?"
        subtitle={`Are you sure you want to delete "${draftForm?.title}"? This will permanently remove the form and all its fields. This action cannot be undone.`}
        type="error"
        buttons={[
          {
            buttonText: 'Yes, Delete Form',
            buttonTextActive: 'Deleting...',
            buttonTextResponse: 'Deleted!',
            variant: 'danger',
            onClick: async () => handleDeleteActiveForm(),
          },
          {
            buttonText: 'Cancel',
            variant: 'secondary',
            onClick: () => setShowDeleteConfirm(false),
          },
        ]}
      />

      <PopupDynamic
        isOpen={showEmailErrorPopup}
        onClose={() => setShowEmailErrorPopup(false)}
        title="Missing Email Field"
        subtitle="You must first add an email field (type: email) to your form to enable emails."
        type="error"
        buttons={[
          {
            buttonText: 'Okay',
            variant: 'secondary',
            onClick: () => setShowEmailErrorPopup(false),
          },
        ]}
      />
    </div>
  );
});

export default FormBuilderEditor;