export const useFormDataTemp = (pageId?: string) => {
    const [forms, setForms] = useState<any[]>([])
    const [currentFormId, setCurrentFormId] = useState<string | null>(null)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const run = async () => {
            try {
                const supabase = await getSupabase()

                const { data: mapData } = await supabase
                    .from('form_page_map')
                    .select('form_key')
                    .eq('page_name', pageId)
                    .single()

                const map: any = (mapData as any)?.form_key
                setCurrentFormId(map)

                const { data: formData } = await supabase
                    .from('form_definitions')
                    .select('definition')

                const extracted = formData?.map(row => row.definition.form) || []
                setForms(extracted)

            } finally {
                setLoading(false)
            }
        }

        run()
    }, [pageId])

    return {
        forms,
        currentFormId,
        loading
    }
}


export const updateCurrentForm = async ({
    activeFormId,
    activeFormTitle
}: {
    activeFormId: string | null
    activeFormTitle?: string
}) => {
    try {
        const supabase = await getSupabase()

        if (!activeFormId) return

        const { error } = await supabase
            .from('form_page_map')
            .upsert({
                page_name: PAGE_ID,
                form_key: activeFormId,
                published: false,
                form_name: activeFormTitle || null
            }, {
                onConflict: 'page_name'
            })

        if (error) throw error

        console.log('Saved draft mapping:', {
            page_name: PAGE_ID,
            form_key: activeFormId
        })

    } catch (err) {
        console.error('Failed to save draft:', err)
    }
}