import React, { useState } from 'react';
import './PopupDynamic.css';

export interface PopupButton {
    buttonText: string;
    buttonTextActive?: string;
    buttonTextResponse?: string;
    onClick: () => Promise<void> | void;
    className?: string;
    variant?: 'primary' | 'danger' | 'secondary' | 'success';
    template?: any; // For custom structure or styling
}

export interface PopupDynamicProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    subtitle?: string;
    status?: string | null;
    buttons: PopupButton[];
    type?: 'warning' | 'error' | 'info' | 'success';
}

const PopupDynamic: React.FC<PopupDynamicProps> = ({
    isOpen,
    onClose,
    title,
    subtitle,
    status,
    buttons,
    type = 'warning'
}) => {
    const [activeButtonIndex, setActiveButtonIndex] = useState<number | null>(null);
    const [responseButtonIndex, setResponseButtonIndex] = useState<number | null>(null);

    if (!isOpen) return null;

    const handleButtonClick = async (button: PopupButton, index: number) => {
        if (activeButtonIndex !== null || responseButtonIndex !== null) return;

        setActiveButtonIndex(index);
        try {
            await button.onClick();
            if (button.buttonTextResponse) {
                setResponseButtonIndex(index);
                setActiveButtonIndex(null);
                setTimeout(() => {
                    setResponseButtonIndex(null);
                    onClose();
                }, 1500);
            } else {
                setActiveButtonIndex(null);
                onClose();
            }
        } catch (error) {
            setActiveButtonIndex(null);
            console.error('Popup action failed:', error);
        }
    };

    return (
        <div className="popup-overlay" onClick={onClose}>
            <div className="popup-content" onClick={(e) => e.stopPropagation()}>
                <div className={`popup-icon-header ${type}`}>
                    {type === 'warning' && (
                        <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"></path>
                            <line x1="12" y1="9" x2="12" y2="13"></line>
                            <line x1="12" y1="17" x2="12.01" y2="17"></line>
                        </svg>
                    )}
                    {type === 'error' && (
                        <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <circle cx="12" cy="12" r="10"></circle>
                            <line x1="15" y1="9" x2="9" y2="15"></line>
                            <line x1="9" y1="9" x2="15" y2="15"></line>
                        </svg>
                    )}
                    {type === 'success' && (
                        <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <polyline points="20 6 9 17 4 12"></polyline>
                        </svg>
                    )}
                    {type === 'info' && (
                        <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <circle cx="12" cy="12" r="10"></circle>
                            <line x1="12" y1="16" x2="12" y2="12"></line>
                            <line x1="12" y1="8" x2="12.01" y2="8"></line>
                        </svg>
                    )}
                </div>

                <h3 className="popup-title">{title}</h3>
                {subtitle && <p className="popup-subtitle">{subtitle}</p>}

                <div className="popup-buttons">
                    {buttons.map((btn, index) => {
                        const isActive = activeButtonIndex === index;
                        const hasResponse = responseButtonIndex === index;

                        return (
                            <button
                                key={index}
                                className={`popup-btn ${btn.variant || 'secondary'} ${isActive ? 'active' : ''} ${hasResponse ? 'response' : ''} ${btn.className || ''}`}
                                onClick={() => handleButtonClick(btn, index)}
                                disabled={activeButtonIndex !== null}
                                style={btn.template?.style}
                            >
                                {isActive ? (
                                    <>
                                        <div className="btn-spinner"></div>
                                        {btn.buttonTextActive || btn.buttonText}
                                    </>
                                ) : hasResponse ? (
                                    btn.buttonTextResponse || 'Success'
                                ) : (
                                    btn.buttonText
                                )}
                            </button>
                        );
                    })}
                </div>

                {status && <div className="popup-status">{status}</div>}

                <button className="popup-close-x" onClick={onClose} title="Close">
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <line x1="18" y1="6" x2="6" y2="18"></line>
                        <line x1="6" y1="6" x2="18" y2="18"></line>
                    </svg>
                </button>
            </div>
        </div>
    );
};

export default PopupDynamic;
