import React from 'react'
import './NienKhoa2019Editor.css'
import { Page4bNienKhoa2019Content as NienKhoa2019Content } from '../../contexts/types'
import ImageEditor from './ImageEditor'
import SectionLockControl from './SectionLockControl'

type NienKhoa2019EditorProps = {
    data: NienKhoa2019Content
    onChange: (data: Partial<NienKhoa2019Content>) => void
}

const NienKhoa2019Editor: React.FC<NienKhoa2019EditorProps> = ({ data, onChange }) => {

    const updateCurriculumItem = (side: 'left' | 'right', index: number, value: string) => {
        const newItems = [...data.curriculum[side].items]
        newItems[index] = value
        onChange({
            curriculum: {
                ...data.curriculum,
                [side]: {
                    ...data.curriculum[side],
                    items: newItems
                }
            }
        })
    }

    const addCurriculumItem = (side: 'left' | 'right') => {
        const newItems = [...data.curriculum[side].items, 'New curriculum item']
        onChange({
            curriculum: {
                ...data.curriculum,
                [side]: {
                    ...data.curriculum[side],
                    items: newItems
                }
            }
        })
    }

    const removeCurriculumItem = (side: 'left' | 'right', index: number) => {
        const newItems = data.curriculum[side].items.filter((_, i) => i !== index)
        onChange({
            curriculum: {
                ...data.curriculum,
                [side]: {
                    ...data.curriculum[side],
                    items: newItems
                }
            }
        })
    }

    return (
        <div className="nien-khoa-2019-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Niên Khóa 2019-2022</h2>
                    <SectionLockControl locked={data.locked} onToggle={(locked) => onChange({ locked })} />
                </div>
                <p className="editor-subtitle">Manage curriculum content and images</p>
            </div>

            <div className={`editor-form ${data.locked ? 'locked-section' : ''}`} style={data.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}>
                <div className="form-section">
                    <div className="form-group">
                        <label className="form-label">Section Title</label>
                        <input
                            type="text"
                            className={`form-input ${data.title.length > 80 ? 'input-error' : ''}`}
                            value={data.title}
                            onChange={(e) => onChange({ title: e.target.value })}
                        />
                        <div className="input-counter">
                            <span className={data.title.length > 80 ? 'text-danger' : ''}>
                                {data.title.length}/80
                            </span>
                        </div>
                    </div>

                    <ImageEditor
                        label="Desktop Image"
                        value={data.imageDesktop}
                        onChange={(val) => onChange({ imageDesktop: val })}
                        aspectRatio="landscape"
                    />

                    <ImageEditor
                        label="Mobile Image"
                        value={data.imageMobile}
                        onChange={(val) => onChange({ imageMobile: val })}
                        aspectRatio="portrait"
                    />

                    <div className="form-group" style={{ marginTop: '1rem' }}>
                        <label className="form-label">Image Position (Desktop)</label>
                        <div className="radio-group" style={{ display: 'flex', gap: '1.5rem' }}>
                            <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', fontSize: '0.9rem' }}>
                                <input
                                    type="radio"
                                    name="nk2019-img-pos"
                                    checked={!data.imagePosition || data.imagePosition === 'left'}
                                    onChange={() => onChange({ imagePosition: 'left' })}
                                />
                                Image Left (default)
                            </label>
                            <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', fontSize: '0.9rem' }}>
                                <input
                                    type="radio"
                                    name="nk2019-img-pos"
                                    checked={data.imagePosition === 'right'}
                                    onChange={() => onChange({ imagePosition: 'right' })}
                                />
                                Image Right
                            </label>
                        </div>
                    </div>
                </div>

                <div className="form-section">
                    <div className="section-header">
                        <h3 className="section-title">Curriculum Content</h3>
                    </div>

                    <div className="curriculum-grid">
                        <div className="curriculum-column">
                            <div className="sub-section">
                                <div className="sub-section-header">
                                    <h4>Left Column</h4>
                                    <button className="btn-mini-add" onClick={() => addCurriculumItem('left')}>
                                        + Add Item
                                    </button>
                                </div>
                                <div className="curriculum-items">
                                    {data.curriculum.left.items.map((item, index) => (
                                        <div key={index} className="curriculum-item">
                                            <div className="mini-item-container">
                                                <div className="mini-item-row">
                                                    <input
                                                        type="text"
                                                        className={`form-input mini ${item.length > 100 ? 'input-error' : ''}`}
                                                        value={item}
                                                        onChange={(e) => updateCurriculumItem('left', index, e.target.value)}
                                                    />
                                                    <button
                                                        className="btn-mini-delete"
                                                        onClick={() => removeCurriculumItem('left', index)}
                                                    >
                                                        ×
                                                    </button>
                                                </div>
                                                <div className="input-counter">
                                                    <span className={item.length > 100 ? 'text-danger' : ''}>
                                                        {item.length}/100
                                                    </span>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>

                        <div className="curriculum-column">
                            <div className="sub-section">
                                <div className="sub-section-header">
                                    <h4>Right Column</h4>
                                    <button className="btn-mini-add" onClick={() => addCurriculumItem('right')}>
                                        + Add Item
                                    </button>
                                </div>
                                <div className="curriculum-items">
                                    {data.curriculum.right.items.map((item, index) => (
                                        <div key={index} className="curriculum-item">
                                            <div className="mini-item-container">
                                                <div className="mini-item-row">
                                                    <input
                                                        type="text"
                                                        className={`form-input mini ${item.length > 100 ? 'input-error' : ''}`}
                                                        value={item}
                                                        onChange={(e) => updateCurriculumItem('right', index, e.target.value)}
                                                    />
                                                    <button
                                                        className="btn-mini-delete"
                                                        onClick={() => removeCurriculumItem('right', index)}
                                                    >
                                                        ×
                                                    </button>
                                                </div>
                                                <div className="input-counter">
                                                    <span className={item.length > 100 ? 'text-danger' : ''}>
                                                        {item.length}/100
                                                    </span>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

export default NienKhoa2019Editor