function spacesToHyphens( input: string): string {
  return input.replace(/\s+/g, '-');
}
function removeVietnameseTones(str: string) {
  return str
    .normalize("NFD") // split letters + accents
    .replace(/[\u0300-\u036f]/g, "") // remove accents
    .replace(/đ/g, "d")
    .replace(/Đ/g, "D");
}

export function formatIdLatinKebab(str: string) {
  return spacesToHyphens(removeVietnameseTones(str)).toLowerCase();
}