import React, { useState } from 'react'
import './ScriptureEditor.css'
import { ScriptureContent, ScriptureCard, ScriptureGroup, ScriptureItem } from '../../contexts/types'
import ImageEditor from './ImageEditor'
import PopupDynamic from '../modals/PopupDynamic'
import SectionLockControl from './SectionLockControl'

type ScriptureEditorProps = {
    data: ScriptureContent
    onChange: (data: Partial<ScriptureContent>) => void
}

const ScriptureEditor: React.FC<ScriptureEditorProps> = ({ data, onChange }) => {
    const [editingCardId, setEditingCardId] = useState<string | null>(null)
    const [deleteGroupInfo, setDeleteGroupInfo] = useState<{ cardId: string, groupId: string } | null>(null)

    const updateCard = (cardId: string, updates: Partial<ScriptureCard>) => {
        const updatedCards = data.cards.map(card =>
            card.id === cardId ? { ...card, ...updates } : card
        )
        onChange({ cards: updatedCards })
    }

    const addGroup = (cardId: string) => {
        const card = data.cards.find(c => c.id === cardId)
        if (!card) return

        const newGroup: ScriptureGroup = {
            id: `group-${Date.now()}`,
            title: 'New Group',
            items: [{ id: `item-${Date.now()}`, label: 'New Item ›' }]
        }
        updateCard(cardId, { groups: [...card.groups, newGroup] })
    }

    const updateGroup = (cardId: string, groupId: string, updates: Partial<ScriptureGroup>) => {
        const card = data.cards.find(c => c.id === cardId)
        if (!card) return

        const updatedGroups = card.groups.map(group =>
            group.id === groupId ? { ...group, ...updates } : group
        )
        updateCard(cardId, { groups: updatedGroups })
    }

    const removeGroup = (cardId: string, groupId: string) => {
        const card = data.cards.find(c => c.id === cardId)
        if (!card) return

        const updatedGroups = card.groups.filter(group => group.id !== groupId)
        updateCard(cardId, { groups: updatedGroups })
    }

    const updateItem = (cardId: string, groupId: string, itemId: string, updates: Partial<ScriptureItem>) => {
        const card = data.cards.find(c => c.id === cardId)
        if (!card) return

        const group = card.groups.find(g => g.id === groupId)
        if (!group) return

        const updatedItems = group.items.map(item =>
            item.id === itemId ? { ...item, ...updates } : item
        )
        updateGroup(cardId, groupId, { items: updatedItems })
    }

    const addItem = (cardId: string, groupId: string) => {
        const card = data.cards.find(c => c.id === cardId)
        if (!card) return

        const group = card.groups.find(g => g.id === groupId)
        if (!group) return

        const newItem: ScriptureItem = {
            id: `item-${Date.now()}`,
            label: 'New Item ›',
            href: ''
        }
        updateGroup(cardId, groupId, { items: [...group.items, newItem] })
    }

    const removeItem = (cardId: string, groupId: string, itemId: string) => {
        const card = data.cards.find(c => c.id === cardId)
        if (!card) return

        const group = card.groups.find(g => g.id === groupId)
        if (!group) return

        const updatedItems = group.items.filter(item => item.id !== itemId)
        updateGroup(cardId, groupId, { items: updatedItems })
    }

    return (
        <div className="scripture-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Scripture Library</h2>
                    <SectionLockControl locked={data.locked} onToggle={(locked) => onChange({ locked })} />
                </div>
                <p className="editor-subtitle">Manage Kinh, Luật, Luận sections and lists</p>
            </div>

            <div className={`editor-form ${data.locked ? 'locked-section' : ''}`} style={data.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}>
                <div className="form-group">
                    <label className="form-label">Section Main Title</label>
                    <textarea
                        className="form-input"
                        rows={2}
                        value={data.sectionTitle}
                        onChange={(e) => onChange({ sectionTitle: e.target.value })}
                        placeholder="Use \n for line breaks"
                    />
                </div>

                <div className="form-group">
                    <ImageEditor
                        label="Background Image"
                        value={data.backgroundImage}
                        onChange={(url) => onChange({ backgroundImage: url })}
                        aspectRatio="landscape"
                    />
                </div>

                <div className="cards-list">
                    {data.cards.map((card) => (
                        <div key={card.id} className={`card-block ${editingCardId === card.id ? 'active' : ''}`}>
                            <div className="card-block-header">
                                <span className="item-label">{card.title}</span>
                                <button
                                    className="btn-action edit"
                                    onClick={() => setEditingCardId(editingCardId === card.id ? null : card.id)}
                                >
                                    {editingCardId === card.id ? 'Close' : 'Edit'}
                                </button>
                            </div>

                            {editingCardId === card.id && (
                                <div className="card-block-editor">
                                    <div className="form-group">
                                        <label className="form-label">Card Title</label>
                                        <input
                                            type="text"
                                            className="form-input"
                                            value={card.title}
                                            onChange={(e) => updateCard(card.id, { title: e.target.value })}
                                        />
                                    </div>

                                    <div className="groups-list">
                                        <div className="sub-section-header">
                                            <h4>Scripture Groups</h4>
                                            <button className="btn-mini-add" onClick={() => addGroup(card.id)}>+ Add Group</button>
                                        </div>

                                        {card.groups.map((group) => (
                                            <div key={group.id} className="group-edit-box">
                                                <div className="group-edit-header">
                                                    <input
                                                        type="text"
                                                        className="form-input mini group-title-input"
                                                        placeholder="Group Title (Optional)"
                                                        value={group.title || ''}
                                                        onChange={(e) => updateGroup(card.id, group.id, { title: e.target.value })}
                                                    />
                                                    <button className="btn-mini-delete" onClick={() => setDeleteGroupInfo({ cardId: card.id, groupId: group.id })}>Remove Group</button>
                                                </div>

                                                <div className="items-list-editor">
                                                    {group.items.map((item) => (
                                                        <div key={item.id} className="item-row">
                                                            <div className="item-fields">
                                                                <input
                                                                    type="text"
                                                                    className="form-input mini"
                                                                    placeholder="Item label"
                                                                    value={item.label}
                                                                    onChange={(e) => updateItem(card.id, group.id, item.id, { label: e.target.value })}
                                                                />
                                                                <input
                                                                    type="text"
                                                                    className="form-input mini item-link-input"
                                                                    placeholder="Link URL (/education/... or https://...)"
                                                                    value={item.href || ''}
                                                                    onChange={(e) => updateItem(card.id, group.id, item.id, { href: e.target.value })}
                                                                    spellCheck={false}
                                                                />
                                                            </div>
                                                            <button className="btn-mini-delete-icon" onClick={() => removeItem(card.id, group.id, item.id)} title="Delete Item">
                                                                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                                    <polyline points="3 6 5 6 21 6"></polyline>
                                                                    <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                                                </svg>
                                                            </button>
                                                        </div>
                                                    ))}
                                                    <button className="btn-link-add" onClick={() => addItem(card.id, group.id)}>+ Add Item</button>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </div>

            <PopupDynamic
                isOpen={!!deleteGroupInfo}
                onClose={() => setDeleteGroupInfo(null)}
                title="Remove Scripture Group?"
                subtitle={`Are you sure you want to remove this group? All scripture links within this group will be permanently deleted.`}
                type="error"
                buttons={[
                    {
                        buttonText: "Yes, Remove Group",
                        buttonTextActive: "Removing...",
                        buttonTextResponse: "Removed!",
                        variant: "danger",
                        onClick: async () => {
                            if (deleteGroupInfo) {
                                removeGroup(deleteGroupInfo.cardId, deleteGroupInfo.groupId);
                                setDeleteGroupInfo(null);
                            }
                        }
                    },
                    {
                        buttonText: "Cancel",
                        variant: "secondary",
                        onClick: () => setDeleteGroupInfo(null)
                    }
                ]}
            />
        </div>
    )
}

export default ScriptureEditor
