import React from 'react'
import './BonDaiTongChiEditor.css'
import { BonDaiTongChiContent, TongChiItem } from '../../contexts/types'
import { FaHandshake, FaBrain, FaPray } from "react-icons/fa"
import { IoEarOutline } from "react-icons/io5"
import ImageEditor from './ImageEditor'
import SectionLockControl from './SectionLockControl'

type BonDaiTongChiEditorProps = {
    data: BonDaiTongChiContent
    onChange: (data: Partial<BonDaiTongChiContent>) => void
}

const icons = [
    { id: 'handshake', icon: <FaHandshake /> },
    { id: 'ear', icon: <IoEarOutline /> },
    { id: 'brain', icon: <FaBrain /> },
    { id: 'pray', icon: <FaPray /> }
]

const BonDaiTongChiEditor: React.FC<BonDaiTongChiEditorProps> = ({ data, onChange }) => {

    const handleItemChange = (index: number, field: keyof TongChiItem, value: any) => {
        const newItems = [...data.items]
        newItems[index] = { ...newItems[index], [field]: value }
        onChange({ items: newItems })
    }

    return (
        <div className="tong-chi-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Bốn Đại Tông Chỉ</h2>
                    <SectionLockControl locked={data.locked} onToggle={(locked) => onChange({ locked })} />
                </div>
                <p className="editor-subtitle">Update the four core principles section</p>
            </div>

            <div className={`editor-form ${data.locked ? 'locked-section' : ''}`} style={data.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}>
                {/* Header Section */}
                <div className="editor-section">
                    <div className="editor-section-title">Section Header</div>
                    <div className="form-group">
                        <label className="form-label">Title</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.title}
                            onChange={(e) => onChange({ title: e.target.value })}
                        />
                    </div>
                    <div className="form-group">
                        <label className="form-label">Subtitle</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.subtitle}
                            onChange={(e) => onChange({ subtitle: e.target.value })}
                        />
                    </div>

                    <ImageEditor
                        label="Desktop Background Image"
                        hint="Main background for the section"
                        value={data.backgroundImage}
                        onChange={(val) => onChange({ backgroundImage: val })}
                        aspectRatio="landscape"
                    />

                    <ImageEditor
                        label="Mobile Background Image"
                        hint="Background for mobile devices"
                        value={data.mobileBackgroundImage}
                        onChange={(val) => onChange({ mobileBackgroundImage: val })}
                        aspectRatio="portrait"
                    />
                </div>

                {/* Items Section */}
                <div className="editor-section">
                    <div className="editor-section-title">Principle Cards</div>
                    <div className="items-list">
                        {data.items.map((item, index) => (
                            <div key={item.id} className="item-card">
                                <div className="form-group">
                                    <label className="form-label">List Item Text</label>
                                    <input
                                        type="text"
                                        className="form-input"
                                        value={item.title}
                                        onChange={(e) => handleItemChange(index, 'title', e.target.value)}
                                    />
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    )
}

export default BonDaiTongChiEditor
