import React, { useEffect, useState } from 'react'
import './SubmissionsEditor.css'
import { useFormSubmissions } from '../ppm/forms/useFormSubmissions';
import { useExportSubmissionsCSV } from '../ppm/forms/useExportSubmissionsCSV';
import { getSupabase } from '../../database/supabase';

const SubmissionsEditor: React.FC = () => {
    const [selectedId, setSelectedId] = useState<string | null>(null);

    const {
        rows: formRows,
        loading: formLoading,
        error: formError,
        reload: reloadForms
    } = useFormSubmissions();

    useEffect(() => {
        console.log("Loading:", formLoading);
        if (formError) console.error("Error:", formError);
        if (formRows.length > 0) {
            console.log("FORM SUBMISSIONS:", formRows);
        }
    }, [formRows, formLoading, formError]);

    const selectedSubmission = formRows.find((s: any) => s.id === selectedId);

    const [editData, setEditData] = useState<any>({});
    const [isSaving, setIsSaving] = useState(false);

    // 🔥 CSV STATE
    const [csvReady, setCsvReady] = useState(false);
    const [loadingCSVPrep, setLoadingCSVPrep] = useState(false);

    const { exportCSV, loading: csvLoading } = useExportSubmissionsCSV({
        pageSize: 500
    });

    const prepareCSV = async () => {
        try {
            setLoadingCSVPrep(true);

            const supabase = await getSupabase();

            await supabase
                .from("form_submissions")
                .select("id")
                .limit(1);

            setCsvReady(true);
        } catch (err) {
            console.error(err);
        } finally {
            setLoadingCSVPrep(false);
        }
    };

    useEffect(() => {
        if (selectedSubmission?.data) {
            setEditData(selectedSubmission.data);
        }
    }, [selectedSubmission]);

    const handleChange = (key: string, value: any) => {
        setEditData((prev: any) => ({
            ...prev,
            [key]: value
        }));
    };

    const handleSave = async () => {
        if (!selectedSubmission) return;

        try {
            setIsSaving(true);

            const supabase = await getSupabase();

            const { error } = await supabase
                .from('form_submissions')
                .update({ data: editData })
                .eq('id', selectedSubmission.id);

            if (error) throw error;

            await reloadForms();
            alert("Saved successfully");

        } catch (err) {
            console.error(err);
            alert("Save failed");
        } finally {
            setIsSaving(false);
        }
    };

    const truncateMessage = (msg: string) => {
        if (!msg) return "";
        if (msg.length <= 70) return msg;
        return msg.substring(0, 70) + "...";
    };

    const formatDate = (dateStr: string) => {
        if (!dateStr) return "";
        const iso = dateStr.replace(" ", "T");
        const date = new Date(iso);
        return date.toLocaleString('en-GB', {
            day: '2-digit',
            month: 'short',
            year: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    if (selectedSubmission) {
        return (
            <div className="submissions-editor">
                <div className="editor-header-title">
                    <button className="btn-back" onClick={() => setSelectedId(null)}>
                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <line x1="19" y1="12" x2="5" y2="12"></line>
                            <polyline points="12 19 5 12 12 5"></polyline>
                        </svg>
                        Back to List
                    </button>
                    <h2>Submission Details</h2>
                </div>

                <div className="submission-detail-container">
                    <div className="detail-header">
                        <span className="col-form-name">{selectedSubmission.form_id}</span>
                        <span className="col-date">{formatDate(selectedSubmission.created_at)}</span>
                    </div>

                    <div className="detail-content">
                        <div className="detail-info-grid">

                            <div className="info-item">
                                <span className="info-label">Form Name</span>
                                <span className="info-value">{selectedSubmission.form_id}</span>
                            </div>

                            <div className="info-item">
                                <span className="info-label">Date Submitted</span>
                                <span className="info-value">{formatDate(selectedSubmission.created_at)}</span>
                            </div>

                            <div className="info-item">
                                <span className="info-label">Email Address</span>
                                <span className="info-value">
                                    {selectedSubmission.data?.email ? (
                                    <a
                                        href={`mailto:${selectedSubmission.data?.email}`}
                                        style={{
                                        color: 'inherit',
                                        textDecoration: 'none'
                                        }}
                                        onMouseEnter={(e) => {
                                        e.currentTarget.style.textDecoration = 'underline';
                                        }}
                                        onMouseLeave={(e) => {
                                        e.currentTarget.style.textDecoration = 'none';
                                        }}
                                    >
                                        {selectedSubmission.data?.email}
                                    </a>
                                    ) : (
                                    <>-</>
                                    )}

                                
                                </span>
                            </div>

                        </div>

                        <div className="detail-message-section">
                            <span className="detail-message-label">Data</span>
                           <div className="detail-message-body">

    {Object.entries(selectedSubmission.data || {}).map(([key, value]) => (
        <div
            key={key}
            style={{
                marginBottom: 12,
                paddingBottom: 8,
                borderBottom: "1px solid #eee"
            }}
        >
            <div
                style={{
                    fontSize: 12,
                    opacity: 0.6,
                    marginBottom: 2
                }}
            >
                {key}
            </div>

            <input
                value={editData?.[key] ?? ""}
                onChange={(e) => handleChange(key, e.target.value)}
                style={{
                    width: "100%",
                    fontSize: 14,
                    fontWeight: 400,
                    lineHeight: 1.5,
                    padding: "6px 8px",
                    border: "1px solid #ddd",
                    borderRadius: 6
                }}
            />
        </div>
    ))}

</div>

<div style={{ marginTop: 16 }}>
    <button
        onClick={handleSave}
        disabled={isSaving}
        style={{
            padding: "8px 14px",
            background: "#111",
            color: "#fff",
            border: "none",
            borderRadius: 6,
            cursor: "pointer"
        }}
    >
        {isSaving ? "Saving..." : "Save Changes"}
    </button>
</div>

                        </div>

                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="submissions-editor">
            <div
                className="editor-header-title"
                style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    flexWrap: "wrap",
                    gap: 10
                }}
            >
                <div>
                    <h2>Form Submissions</h2>
                    <p className="editor-subtitle">Review and manage all incoming form responses</p>
                </div>

                <button
                    onClick={csvReady ? exportCSV : prepareCSV}
                    disabled={loadingCSVPrep || csvLoading}
                    style={{
                        padding: "8px 14px",
                        background: csvReady ? "#0a7" : "#111",
                        color: "#fff",
                        border: "none",
                        borderRadius: 6,
                        cursor: "pointer",
                        whiteSpace: "nowrap"
                    }}
                >
                    {loadingCSVPrep
                        ? "Creating..."
                        : csvLoading
                            ? "Downloading..."
                            : csvReady
                                ? "Download CSV"
                                : "Export CSV"}
                </button>
            </div>

            {formLoading && <p>Loading...</p>}
            {formError && <p style={{ color: "red" }}>{formError}</p>}

            <div className="submissions-table-container">
                <table className="submissions-table">
                    <thead>
                        <tr>
                            <th style={{ width: '200px' }}>Date</th>
                            <th style={{ width: '250px' }}>Email</th>
                            <th style={{ width: '150px' }}>Form Name</th>
                            <th>Message Preview</th>
                        </tr>
                    </thead>

                    <tbody>
                        {formRows
                            .sort((a: any, b: any) => b.created_at.localeCompare(a.created_at))
                            .map((sub: any) => (
                                <tr key={sub.id} onClick={() => setSelectedId(sub.id)}>

                                    <td className="col-date" data-label="Date">
                                        {formatDate(sub.created_at)}
                                    </td>

                                    <td className="col-email" data-label="Email">
                                        {sub.data?.email || "-"}
                                    </td>

                                    <td data-label="Form">
                                        <span className="col-form-name">{sub.form_id}</span>
                                    </td>

                                    <td className="col-message" data-label="Message">
                                        {<td className="col-message" data-label="Message">
    {truncateMessage(
        Object.entries(sub.data || {})
            .filter(([key]) => key !== "email")
            .map(([, value]) => String(value))
            .join(", ")
    )}
</td>}
                                    </td>

                                </tr>
                            ))}
                    </tbody>

                </table>

                {formRows.length === 0 && !formLoading && (
                    <div className="empty-state">
                        <p>No submissions found.</p>
                    </div>
                )}

            </div>
        </div>
    );
};

export default SubmissionsEditor;