import { useState, useEffect } from 'react';
import { Form, FormField } from '../components/ppm/cms/form-builder/FormBuilderTypes';
import { useResolved } from '../ppm/util/ResolvedContentContext';

export const useFormDataLocalstorage = (
  localStorageKey: string,
  meta?: { version?: number; clear?: boolean }
) => {

  const [form, setForm] = useState<Form | null>(null);
  const [loading, setLoading] = useState(true);

  const content = !!meta
    ? useResolved().pages.page3.ghiDanhThienContent
    : undefined;

  const saveToStorage = (updatedForm: Form | null) => {
    if (!updatedForm) {
      localStorage.removeItem(localStorageKey);
      setForm(null);
      return;
    }

    localStorage.setItem(localStorageKey, JSON.stringify(updatedForm));
    setForm(updatedForm);
  };

  useEffect(() => {
    let mounted = true;

    const run = async () => {
      setLoading(true);

      let localForm: Form | null = null;

      // 🧹 CLEAR MODE
      if (meta?.clear) {
        localStorage.removeItem(localStorageKey);

        if (!mounted) return;

        setForm(null);
        setLoading(false);
        return;
      }

      const raw = localStorage.getItem(localStorageKey);

      if (raw) {
        try {
          const parsed = JSON.parse(raw);
          if (parsed && typeof parsed === 'object') {
            localForm = {
              ...parsed,
              source: 'localstorage'
            };
          }
        } catch {
          localStorage.removeItem(localStorageKey);
        }
      }

      // TEST MODE (overwrite)
      if (meta && !meta.clear && content?.form) {
        localForm = {
          ...content.form,
          source: 'localstorage',
          ...(meta.version !== undefined ? { version: meta.version } : {})
        } as Form;

        localStorage.setItem(localStorageKey, JSON.stringify(localForm));
      }

      if (!mounted) return;

      setForm(localForm);
      setLoading(false);
    };

    run();

    return () => {
      mounted = false;
    };
  }, [localStorageKey, meta?.version, meta?.clear, content]);

  const updateForm = (updates: Partial<Form>) => {
    if (!form) return;
    const updated = { ...form, ...updates, source: 'localstorage' };
    saveToStorage(updated);
  };

  const deleteForm = () => {
    saveToStorage(null);
  };

  const renameForm = (newTitle: string) => {
    updateForm({ title: newTitle });
  };

  const addField = (field: FormField) => {
    if (!form) return;
    const updatedFields = [...form.fields, field];
    updateForm({ fields: updatedFields });
  };

  const removeField = (fieldId: string) => {
    if (!form) return;
    const updatedFields = form.fields.filter(f => f.id !== fieldId);
    updateForm({ fields: updatedFields });
  };

  return {
    form,
    loading,
    updateForm,
    deleteForm,
    renameForm,
    addField,
    removeField
  };
};