
import React, { useState } from 'react'
import './MusicEditor.css'
import { MusicContent, MusicAlbum, MusicTrack } from '../../contexts/types'
import ImageEditor from './ImageEditor'
import PopupDynamic from '../modals/PopupDynamic'
import SectionLockControl from './SectionLockControl'
import RichTextEditor from './RichTextEditor'

type MusicEditorProps = {
    data: MusicContent
    onChange: (data: Partial<MusicContent>) => void
}

const MusicEditor: React.FC<MusicEditorProps> = ({ data, onChange }) => {
    const [editingAlbumId, setEditingAlbumId] = useState<string | null>(null)
    const [editingTrackId, setEditingTrackId] = useState<string | null>(null)
    const [deleteAlbumId, setDeleteAlbumId] = useState<string | null>(null)

    const updateAlbum = (id: string, updates: Partial<MusicAlbum>) => {
        const updatedAlbums = data.albums.map(album => {
            if (album.id === id) {
                return { ...album, ...updates }
            }
            return album
        })
        onChange({ albums: updatedAlbums })
    }

    const addAlbum = () => {
        const newAlbum: MusicAlbum = {
            id: `album-${Date.now()}`,
            cateid: 0,
            name: 'New Album',
            thumbnail: '',
            tracks: []
        }
        onChange({ albums: [newAlbum, ...data.albums] })
        setEditingAlbumId(newAlbum.id)
    }

    const removeAlbum = (id: string) => {
        const updatedAlbums = data.albums.filter(album => album.id !== id)
        onChange({ albums: updatedAlbums })
    }

    const addTrack = (albumId: string) => {
        const newTrack: MusicTrack = {
            id: `track-${Date.now()}`,
            slug: `track-${Date.now()}`,
            title: 'New Track',
            lyrics: '',
            composer: '',
            musician: '',
            arrangement: '',
            singer: '',
            category: '',
            audioFile: '',
            imageFile: '',
            image: ''
        }
        const updatedAlbums = data.albums.map(album => {
            if (album.id === albumId) {
                return { ...album, tracks: [...album.tracks, newTrack] }
            }
            return album
        })
        onChange({ albums: updatedAlbums })
        setEditingTrackId(newTrack.id)
    }

    const updateTrack = (albumId: string, trackId: string, updates: Partial<MusicTrack>) => {
        const updatedAlbums = data.albums.map(album => {
            if (album.id === albumId) {
                const updatedTracks = album.tracks.map(track => {
                    if (track.id === trackId) {
                        return { ...track, ...updates }
                    }
                    return track
                })
                return { ...album, tracks: updatedTracks }
            }
            return album
        })
        onChange({ albums: updatedAlbums })
    }

    const removeTrack = (albumId: string, trackId: string) => {
        const updatedAlbums = data.albums.map(album => {
            if (album.id === albumId) {
                const updatedTracks = album.tracks.filter(track => track.id !== trackId)
                return { ...album, tracks: updatedTracks }
            }
            return album
        })
        onChange({ albums: updatedAlbums })
    }

    return (
        <div className="music-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Music Content</h2>
                    <SectionLockControl
                        locked={data.locked}
                        onToggle={(newLocked) => onChange({ locked: newLocked })}
                    />
                </div>
                <p className="editor-subtitle">Manage music albums and tracks</p>
            </div>

            <div className={`editor-form ${data.locked ? 'locked-section' : ''}`} style={data.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}>
                <div className="form-section">
                    <div className="form-group">
                        <label className="form-label">Section Title</label>
                        <input
                            type="text"
                            className="form-input"
                            value={data.sectionTitle}
                            onChange={(e) => onChange({ sectionTitle: e.target.value })}
                        />
                    </div>
                </div>

                <div className="form-section">
                    <div className="section-header">
                        <h3 className="section-title">Music Albums</h3>
                        <button className="btn-add-item" onClick={addAlbum}>+ Add Album</button>
                    </div>

                    <div className="albums-list">
                        {data.albums.map(album => (
                            <div key={album.id} className={`album-card ${editingAlbumId === album.id ? 'active' : ''}`}>
                                <div className="album-header">
                                    <div className="album-info">
                                        <span className="item-label">{album.name}</span>
                                        <span style={{ marginLeft: '10px', fontSize: '12px', color: '#999' }}>({album.tracks.length} tracks)</span>
                                    </div>
                                    <div className="item-actions">
                                        <button className="btn-action edit" onClick={() => setEditingAlbumId(editingAlbumId === album.id ? null : album.id)}>
                                            {editingAlbumId === album.id ? 'Close' : 'Edit'}
                                        </button>
                                        <button className="btn-action delete" onClick={() => setDeleteAlbumId(album.id)}>Delete</button>
                                    </div>
                                </div>

                                {editingAlbumId === album.id && (
                                    <div className="album-editor-expanded">
                                        <div className="form-group">
                                            <label className="form-label">Album Name</label>
                                            <input
                                                type="text"
                                                className="form-input"
                                                value={album.name}
                                                onChange={(e) => updateAlbum(album.id, { name: e.target.value })}
                                            />
                                        </div>
                                        <ImageEditor
                                            label="Album Thumbnail"
                                            value={album.thumbnail}
                                            onChange={(url) => updateAlbum(album.id, { thumbnail: url })}
                                            aspectRatio="square"
                                        />

                                        <div className="tracks-container" style={{ marginTop: '20px' }}>
                                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
                                                <h4>Tracks</h4>
                                                <button className="btn-add-track" onClick={() => addTrack(album.id)}>+ Add Track</button>
                                            </div>
                                            <div className="tracks-list">
                                                {album.tracks.map(track => (
                                                    <div key={track.id} className="track-wrapper" style={{ marginBottom: '10px', border: '1px solid #f0f0f0', borderRadius: '8px', padding: '10px' }}>
                                                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                                            <span className="track-info">{track.title}</span>
                                                            <div className="item-actions">
                                                                <button className="btn-action edit" onClick={() => setEditingTrackId(editingTrackId === track.id ? null : track.id)}>
                                                                    {editingTrackId === track.id ? 'Hide' : 'Edit'}
                                                                </button>
                                                                <button className="btn-action delete" style={{ padding: '4px 8px' }} onClick={() => removeTrack(album.id, track.id)}>×</button>
                                                            </div>
                                                        </div>

                                                        {editingTrackId === track.id && (
                                                            <div className="track-editor-nested" style={{ marginTop: '10px', display: 'flex', flexDirection: 'column', gap: '10px', background: '#fff', padding: '15px', borderRadius: '8px' }}>
                                                                <div className="form-group">
                                                                    <label className="form-label">Track Title</label>
                                                                    <input type="text" className="form-input" value={track.title} onChange={(e) => updateTrack(album.id, track.id, { title: e.target.value })} />
                                                                </div>
                                                                <div className="form-group">
                                                                    <label className="form-label">Singer</label>
                                                                    <input type="text" className="form-input" value={track.singer} onChange={(e) => updateTrack(album.id, track.id, { singer: e.target.value })} />
                                                                </div>
                                                                <div className="form-group">
                                                                    <label className="form-label">Audio File URL</label>
                                                                    <input type="text" className="form-input" value={track.audioFile} onChange={(e) => updateTrack(album.id, track.id, { audioFile: e.target.value })} />
                                                                </div>
                                                                 <div className="form-group">
                                                                    <label className="form-label">Lyrics</label>
                                                                    <RichTextEditor 
                                                                        value={track.lyrics} 
                                                                        onChange={(val) => updateTrack(album.id, track.id, { lyrics: val })}
                                                                        placeholder="Track lyrics..."
                                                                        minHeight="150px"
                                                                    />
                                                                </div>
                                                            </div>
                                                        )}
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            <PopupDynamic
                isOpen={!!deleteAlbumId}
                onClose={() => setDeleteAlbumId(null)}
                title="Delete Album?"
                subtitle="Are you sure you want to delete this entire album and all its tracks?"
                type="error"
                buttons={[
                    {
                        buttonText: "Yes, Delete Album",
                        variant: "danger",
                        onClick: async () => {
                            if (deleteAlbumId) {
                                removeAlbum(deleteAlbumId);
                                setDeleteAlbumId(null);
                            }
                        }
                    },
                    {
                        buttonText: "Cancel",
                        variant: "secondary",
                        onClick: () => setDeleteAlbumId(null)
                    }
                ]}
            />
        </div>
    )
}

export default MusicEditor
