import React, { useState } from 'react'
import './ChuyenKhoaATyDamEditor.css'
import { Page6bNienKhoaContent } from '../../contexts/types'
import ImageEditor from './ImageEditor'
import PopupDynamic from '../modals/PopupDynamic'
import SectionLockControl from './SectionLockControl'

type NienKhoaPage6EditorProps = {
    data: Page6bNienKhoaContent
    onChange: (data: Partial<Page6bNienKhoaContent>) => void
}

const NienKhoaPage6Editor: React.FC<NienKhoaPage6EditorProps> = ({ data, onChange }) => {
    const [deleteBlockIndex, setDeleteBlockIndex] = useState<number | null>(null);

    const updateBlock = (blockIndex: number, updates: any) => {
        const newBlocks = [...data.blocks]
        newBlocks[blockIndex] = { ...newBlocks[blockIndex], ...updates }
        onChange({ blocks: newBlocks })
    }

    const addBlock = () => {
        const newBlock = {
            id: `block-${Date.now()}`,
            type: 'schedule' as const,
            title: 'New Block',
            imageDesktop: '',
            imageMobile: '',
            schedules: {
                heading: 'New Schedule Heading',
                items: []
            }
        }
        onChange({ blocks: [...data.blocks, newBlock] })
    }

    const removeBlock = (blockIndex: number) => {
        const newBlocks = data.blocks.filter((_, i) => i !== blockIndex)
        onChange({ blocks: newBlocks })
    }

    const updateScheduleItem = (blockIndex: number, itemIndex: number, field: string, value: any) => {
        const newBlocks = [...data.blocks]
        const block = newBlocks[blockIndex]
        if (block.type === 'schedule' && block.schedules) {
            const newItems = [...block.schedules.items]
            newItems[itemIndex] = { ...newItems[itemIndex], [field]: value }
            newBlocks[blockIndex] = {
                ...block,
                schedules: {
                    ...block.schedules,
                    items: newItems
                }
            }
            onChange({ blocks: newBlocks })
        }
    }

    const addScheduleItem = (blockIndex: number) => {
        const newBlocks = [...data.blocks]
        const block = newBlocks[blockIndex]
        if (block.type === 'schedule' && block.schedules) {
            const newItem = {
                id: `item-${Date.now()}`,
                dayLabel: 'New Day',
                details: ['New detail']
            }
            newBlocks[blockIndex] = {
                ...block,
                schedules: {
                    ...block.schedules,
                    items: [...block.schedules.items, newItem]
                }
            }
            onChange({ blocks: newBlocks })
        }
    }

    const removeScheduleItem = (blockIndex: number, itemIndex: number) => {
        const newBlocks = [...data.blocks]
        const block = newBlocks[blockIndex]
        if (block.type === 'schedule' && block.schedules) {
            const newItems = block.schedules.items.filter((_, i) => i !== itemIndex)
            newBlocks[blockIndex] = {
                ...block,
                schedules: {
                    ...block.schedules,
                    items: newItems
                }
            }
            onChange({ blocks: newBlocks })
        }
    }

    const updateScheduleDetail = (blockIndex: number, itemIndex: number, detailIndex: number, value: string) => {
        const newBlocks = [...data.blocks]
        const block = newBlocks[blockIndex]
        if (block.type === 'schedule' && block.schedules) {
            const newItems = [...block.schedules.items]
            const newDetails = [...newItems[itemIndex].details]
            newDetails[detailIndex] = value
            newItems[itemIndex] = { ...newItems[itemIndex], details: newDetails }
            newBlocks[blockIndex] = {
                ...block,
                schedules: {
                    ...block.schedules,
                    items: newItems
                }
            }
            onChange({ blocks: newBlocks })
        }
    }

    const addScheduleDetail = (blockIndex: number, itemIndex: number) => {
        const newBlocks = [...data.blocks]
        const block = newBlocks[blockIndex]
        if (block.type === 'schedule' && block.schedules) {
            const newItems = [...block.schedules.items]
            newItems[itemIndex] = {
                ...newItems[itemIndex],
                details: [...newItems[itemIndex].details, 'New detail']
            }
            newBlocks[blockIndex] = {
                ...block,
                schedules: {
                    ...block.schedules,
                    items: newItems
                }
            }
            onChange({ blocks: newBlocks })
        }
    }

    const removeScheduleDetail = (blockIndex: number, itemIndex: number, detailIndex: number) => {
        const newBlocks = [...data.blocks]
        const block = newBlocks[blockIndex]
        if (block.type === 'schedule' && block.schedules) {
            const newItems = [...block.schedules.items]
            const newDetails = newItems[itemIndex].details.filter((_, i) => i !== detailIndex)
            newItems[itemIndex] = { ...newItems[itemIndex], details: newDetails }
            newBlocks[blockIndex] = {
                ...block,
                schedules: {
                    ...block.schedules,
                    items: newItems
                }
            }
            onChange({ blocks: newBlocks })
        }
    }

    const updateCourse = (blockIndex: number, courseIndex: number, field: string, value: string) => {
        const newBlocks = [...data.blocks]
        const block = newBlocks[blockIndex]
        if (block.type === 'course' && block.courses) {
            const newCourses = [...block.courses]
            newCourses[courseIndex] = { ...newCourses[courseIndex], [field]: value }
            newBlocks[blockIndex] = {
                ...block,
                courses: newCourses
            }
            onChange({ blocks: newBlocks })
        }
    }

    const addCourse = (blockIndex: number) => {
        const newBlocks = [...data.blocks]
        const block = newBlocks[blockIndex]
        if (block.type === 'course' && block.courses) {
            const newCourse = {
                id: `course-${Date.now()}`,
                title: 'New Course',
                description: 'New course description'
            }
            newBlocks[blockIndex] = {
                ...block,
                courses: [...block.courses, newCourse]
            }
            onChange({ blocks: newBlocks })
        }
    }

    const removeCourse = (blockIndex: number, courseIndex: number) => {
        const newBlocks = [...data.blocks]
        const block = newBlocks[blockIndex]
        if (block.type === 'course' && block.courses) {
            const newCourses = block.courses.filter((_, i) => i !== courseIndex)
            newBlocks[blockIndex] = {
                ...block,
                courses: newCourses
            }
            onChange({ blocks: newBlocks })
        }
    }

    return (
        <div className="chuyen-khoa-a-ty-dam-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Niên Khóa Page 6</h2>
                    <SectionLockControl locked={data.locked} onToggle={(locked) => onChange({ locked })} />
                </div>
                <p className="editor-subtitle">Manage program blocks and content</p>
            </div>

            <div className={`editor-form ${data.locked ? 'locked-section' : ''}`} style={data.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}>
                <div className="form-section">
                    <div className="section-header">
                        <h3 className="section-title">Content Blocks</h3>
                        <button className="btn-mini-add" onClick={addBlock}>
                            + Add Block
                        </button>
                    </div>

                    {data.blocks.map((block, blockIndex) => (
                        <div key={block.id} className="form-section">
                            <div className="sub-section-header">
                                <h4>Block {blockIndex + 1}: {block.title}</h4>
                                <button
                                    className="btn-mini-delete"
                                    onClick={() => setDeleteBlockIndex(blockIndex)}
                                    title="Delete Block"
                                >
                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                        <polyline points="3 6 5 6 21 6"></polyline>
                                        <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                    </svg>
                                </button>
                            </div>

                            <div className="form-group">
                                <label className="form-label">Block Title</label>
                                <input
                                    type="text"
                                    className="form-input"
                                    value={block.title}
                                    onChange={(e) => updateBlock(blockIndex, { title: e.target.value })}
                                />
                            </div>

                            <div className="form-group">
                                <label className="form-label">Block Type</label>
                                <select
                                    className="form-input"
                                    value={block.type}
                                    onChange={(e) => {
                                        const newType = e.target.value as 'schedule' | 'course'
                                        const updates: any = { type: newType }
                                        if (newType === 'schedule') {
                                            updates.schedules = { heading: 'Schedule Heading', items: [] }
                                            delete updates.courses
                                        } else {
                                            updates.courses = []
                                            delete updates.schedules
                                        }
                                        updateBlock(blockIndex, updates)
                                    }}
                                >
                                    <option value="schedule">Schedule</option>
                                    <option value="course">Course</option>
                                </select>
                            </div>

                            <ImageEditor
                                label="Desktop Image"
                                value={block.imageDesktop}
                                onChange={(val) => updateBlock(blockIndex, { imageDesktop: val })}
                                aspectRatio="landscape"
                            />

                            {block.imageMobile !== undefined && (
                                <ImageEditor
                                    label="Mobile Image"
                                    value={block.imageMobile}
                                    onChange={(val) => updateBlock(blockIndex, { imageMobile: val })}
                                    aspectRatio="landscape"
                                />
                            )}

                            <div className="form-group" style={{ marginTop: '1rem' }}>
                                <label className="form-label">Image Position (Desktop)</label>
                                <div className="radio-group" style={{ display: 'flex', gap: '1.5rem' }}>
                                    <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', fontSize: '0.9rem' }}>
                                        <input
                                            type="radio"
                                            name={`block-pos-${block.id}`}
                                            checked={!block.imagePosition || block.imagePosition === 'right'}
                                            onChange={() => updateBlock(blockIndex, { imagePosition: 'right' })}
                                        />
                                        Image Right (default)
                                    </label>
                                    <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', fontSize: '0.9rem' }}>
                                        <input
                                            type="radio"
                                            name={`block-pos-${block.id}`}
                                            checked={block.imagePosition === 'left'}
                                            onChange={() => updateBlock(blockIndex, { imagePosition: 'left' })}
                                        />
                                        Image Left
                                    </label>
                                </div>
                            </div>

                            {block.type === 'schedule' && block.schedules && (
                                <div className="sub-section">
                                    <div className="form-group">
                                        <label className="form-label">Schedule Heading</label>
                                        <input
                                            type="text"
                                            className="form-input"
                                            value={block.schedules.heading}
                                            onChange={(e) => updateBlock(blockIndex, {
                                                schedules: { ...block.schedules, heading: e.target.value }
                                            })}
                                        />
                                    </div>

                                    <div className="sub-section-header">
                                        <h4>Schedule Items</h4>
                                        <div className="sub-section-actions">
                                            <button className="btn-mini-add" onClick={() => addScheduleItem(blockIndex)}>
                                                + Add Schedule Item
                                            </button>
                                        </div>
                                    </div>

                                    {block.schedules.items.map((item, itemIndex) => (
                                        <div key={item.id} className="curriculum-item">
                                            <div className="mini-item-row" style={{ alignItems: 'center' }}>
                                                <input
                                                    type="text"
                                                    className="form-input mini"
                                                    placeholder="Day Label"
                                                    value={item.dayLabel}
                                                    onChange={(e) => updateScheduleItem(blockIndex, itemIndex, 'dayLabel', e.target.value)}
                                                />
                                                <div className="sub-section-actions">
                                                    <button
                                                        className="btn-mini-add"
                                                        onClick={() => addScheduleDetail(blockIndex, itemIndex)}
                                                    >
                                                        + Add Detail
                                                    </button>
                                                    <button
                                                        className="btn-mini-delete"
                                                        onClick={() => removeScheduleItem(blockIndex, itemIndex)}
                                                        title="Delete Schedule"
                                                    >
                                                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                            <polyline points="3 6 5 6 21 6"></polyline>
                                                            <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                                        </svg>
                                                    </button>
                                                </div>
                                            </div>

                                            <div className="schedule-details">
                                                <h5 style={{ fontSize: '0.75rem', color: '#6b7280', marginBottom: '0.75rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                                                    Details
                                                </h5>
                                                {item.details.map((detail, detailIndex) => (
                                                    <div key={detailIndex} className="mini-item-row">
                                                        <input
                                                            type="text"
                                                            className="form-input mini"
                                                            value={detail}
                                                            onChange={(e) => updateScheduleDetail(blockIndex, itemIndex, detailIndex, e.target.value)}
                                                        />
                                                        <button
                                                            className="btn-mini-delete"
                                                            onClick={() => removeScheduleDetail(blockIndex, itemIndex, detailIndex)}
                                                            title="Delete Detail"
                                                        >
                                                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                                <polyline points="3 6 5 6 21 6"></polyline>
                                                                <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                                            </svg>
                                                        </button>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}

                            {block.type === 'course' && block.courses && (
                                <div className="sub-section">
                                    <div className="sub-section-header">
                                        <h4>Courses</h4>
                                        <button className="btn-mini-add" onClick={() => addCourse(blockIndex)}>
                                            + Add Course
                                        </button>
                                    </div>

                                    {block.courses.map((course, courseIndex) => (
                                        <div key={course.id} className="curriculum-item">
                                            <div className="mini-item-row">
                                                <input
                                                    type="text"
                                                    className="form-input mini"
                                                    placeholder="Course Title"
                                                    value={course.title}
                                                    onChange={(e) => updateCourse(blockIndex, courseIndex, 'title', e.target.value)}
                                                />
                                                <button
                                                    className="btn-mini-delete"
                                                    onClick={() => removeCourse(blockIndex, courseIndex)}
                                                    title="Delete Course"
                                                >
                                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                        <polyline points="3 6 5 6 21 6"></polyline>
                                                        <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                                    </svg>
                                                </button>
                                            </div>
                                            <textarea
                                                className="form-input"
                                                placeholder="Course Description"
                                                value={course.description}
                                                onChange={(e) => updateCourse(blockIndex, courseIndex, 'description', e.target.value)}
                                                rows={3}
                                            />
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </div>

            <PopupDynamic
                isOpen={deleteBlockIndex !== null}
                onClose={() => setDeleteBlockIndex(null)}
                title="Delete Block?"
                subtitle={`Are you sure you want to delete the block "${deleteBlockIndex !== null ? data.blocks[deleteBlockIndex]?.title : ''}"? This action cannot be undone.`}
                type="error"
                buttons={[
                    {
                        buttonText: "Yes, Delete Block",
                        buttonTextActive: "Deleting...",
                        buttonTextResponse: "Deleted!",
                        variant: "danger",
                        onClick: async () => {
                            if (deleteBlockIndex !== null) {
                                removeBlock(deleteBlockIndex);
                                setDeleteBlockIndex(null);
                            }
                        }
                    },
                    {
                        buttonText: "Cancel",
                        variant: "secondary",
                        onClick: () => setDeleteBlockIndex(null)
                    }
                ]}
            />
        </div>
    )
}

export default NienKhoaPage6Editor