
import React, { useState } from 'react'
import './GalleriesEditor.css'
import { GalleriesContent, CollectionItem, ImageBlogItem } from '../../contexts/types'
import ImageEditor from './ImageEditor'
import PopupDynamic from '../modals/PopupDynamic'
import SectionLockControl from './SectionLockControl'
import RichTextEditor from './RichTextEditor'

type GalleriesEditorProps = {
    data: GalleriesContent
    onChange: (data: Partial<GalleriesContent>) => void
}

const GalleriesEditor: React.FC<GalleriesEditorProps> = ({ data, onChange }) => {
    const [activeTab, setActiveTab] = useState<'collections' | 'blogs'>('collections')
    const [editingId, setEditingId] = useState<string | null>(null)
    const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null)

    const addCollection = () => {
        const newItem: CollectionItem = {
            id: `col-${Date.now()}`,
            slug: `album-${Date.now()}`,
            title: 'New Photo Collection',
            description: '',
            excerpt: '',
            body: '',
            category: 'Event',
            image: '',
            isHot: false,
            date: new Date().toLocaleDateString('vi-VN')
        }
        onChange({ collections: [newItem, ...data.collections] })
        setEditingId(newItem.id)
    }

    const addBlog = () => {
        const newItem: ImageBlogItem = {
            id: `blog-${Date.now()}`,
            slug: `blog-${Date.now()}`,
            title: 'New Image Blog',
            body: '',
            image: '',
            date: new Date().toLocaleDateString('vi-VN'),
            link: ''
        }
        onChange({ imageBlogs: [newItem, ...data.imageBlogs] })
        setEditingId(newItem.id)
    }

    const updateCollection = (id: string, updates: Partial<CollectionItem>) => {
        const updated = data.collections.map(item => item.id === id ? { ...item, ...updates } : item)
        onChange({ collections: updated })
    }

    const updateBlog = (id: string, updates: Partial<ImageBlogItem>) => {
        const updated = data.imageBlogs.map(item => item.id === id ? { ...item, ...updates } : item)
        onChange({ imageBlogs: updated })
    }

    const removeCurrent = (id: string) => {
        if (activeTab === 'collections') {
            onChange({ collections: data.collections.filter(i => i.id !== id) })
        } else {
            onChange({ imageBlogs: data.imageBlogs.filter(i => i.id !== id) })
        }
    }

    return (
        <div className="galleries-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Image Galleries</h2>
                    <SectionLockControl
                        locked={data.locked}
                        onToggle={(newLocked) => onChange({ locked: newLocked })}
                    />
                </div>
                <p className="editor-subtitle">Manage photo collections and image-driven blogs</p>
            </div>

            <div className="gallery-tabs">
                <button className={`gallery-tab-btn ${activeTab === 'collections' ? 'active' : ''}`} onClick={() => {setActiveTab('collections'); setEditingId(null)}}>
                    Photo Collections
                </button>
                <button className={`gallery-tab-btn ${activeTab === 'blogs' ? 'active' : ''}`} onClick={() => {setActiveTab('blogs'); setEditingId(null)}}>
                    Image Blogs
                </button>
            </div>

            <div className={`editor-form ${data.locked ? 'locked-section' : ''}`}>
                <div className="form-section">
                    <div className="section-header">
                        <h3 className="section-title">{activeTab === 'collections' ? 'Collections' : 'Blogs'}</h3>
                        <button className="btn-add-item" onClick={activeTab === 'collections' ? addCollection : addBlog}>
                            + Add {activeTab === 'collections' ? 'Collection' : 'Blog'}
                        </button>
                    </div>

                    <div className="gallery-grid">
                        {(activeTab === 'collections' ? data.collections : data.imageBlogs).map(item => (
                            <div key={item.id} className={`gallery-card ${editingId === item.id ? 'active' : ''}`}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <span className="item-label">{item.title}</span>
                                    <div className="item-actions">
                                        <button className="btn-action edit" onClick={() => setEditingId(editingId === item.id ? null : item.id)}>
                                            {editingId === item.id ? 'Close' : 'Edit'}
                                        </button>
                                        <button className="btn-action delete" onClick={() => setDeleteConfirmId(item.id)}>Delete</button>
                                    </div>
                                </div>

                                {editingId === item.id && (
                                    <div className="gallery-item-editor" style={{ marginTop: '20px', display: 'flex', flexDirection: 'column', gap: '15px' }}>
                                        <div className="form-group">
                                            <label className="form-label">Title</label>
                                            <input type="text" className="form-input" value={item.title} onChange={(e) => activeTab === 'collections' ? updateCollection(item.id, {title: e.target.value}) : updateBlog(item.id, {title: e.target.value})} />
                                        </div>
                                        <ImageEditor
                                            label="Feature Image"
                                            value={item.image}
                                            onChange={(url) => activeTab === 'collections' ? updateCollection(item.id, {image: url}) : updateBlog(item.id, {image: url})}
                                            aspectRatio="landscape"
                                        />
                                        <div className="form-group">
                                            <label className="form-label">Date</label>
                                            <input type="text" className="form-input" value={item.date} onChange={(e) => activeTab === 'collections' ? updateCollection(item.id, {date: e.target.value}) : updateBlog(item.id, {date: e.target.value})} />
                                        </div>
                                        {activeTab === 'collections' && (
                                            <div className="form-group">
                                                <label className="form-label">Description</label>
                                                <textarea className="form-input" rows={3} value={(item as CollectionItem).description} onChange={(e) => updateCollection(item.id, {description: e.target.value})} />
                                            </div>
                                        )}
                                        <div className="form-group">
                                            <label className="form-label">Body Content</label>
                                            <RichTextEditor
                                                value={item.body}
                                                onChange={(val) => activeTab === 'collections' ? updateCollection(item.id, {body: val}) : updateBlog(item.id, {body: val})}
                                                placeholder="Enter content..."
                                            />
                                        </div>
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            <PopupDynamic
                isOpen={!!deleteConfirmId}
                onClose={() => setDeleteConfirmId(null)}
                title="Confirm Deletion"
                subtitle="Are you sure you want to delete this item? This cannot be undone."
                type="error"
                buttons={[
                    {
                        buttonText: "Delete",
                        variant: "danger",
                        onClick: async () => {
                            if (deleteConfirmId) {
                                removeCurrent(deleteConfirmId);
                                setDeleteConfirmId(null);
                            }
                        }
                    },
                    {
                        buttonText: "Cancel",
                        variant: "secondary",
                        onClick: () => setDeleteConfirmId(null)
                    }
                ]}
            />
        </div>
    )
}

export default GalleriesEditor
