import React from 'react'
import './HeaderEditor.css'
import { HeaderData } from '../../contexts/CMSContext'
import ImageEditor from './ImageEditor'
import SectionLockControl from './SectionLockControl'

type HeaderEditorProps = {
    data: HeaderData
    onChange: (data: Partial<HeaderData>) => void
}

const HeaderEditor: React.FC<HeaderEditorProps> = ({ data, onChange }) => {
    return (
        <div className="header-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Hero Header</h2>
                    <SectionLockControl
                        locked={data.locked}
                        onToggle={(newLocked) => onChange({ locked: newLocked })}
                    />
                </div>
                <p className="editor-subtitle">Update the main announcement and visual style</p>
            </div>

            <div className="editor-form" style={{
                opacity: data.locked ? 0.5 : 1,
                pointerEvents: data.locked ? 'none' : 'auto',
                transition: 'opacity 0.3s'
            }}>
                {/* Title Input */}
                <div className="form-group">
                    <label htmlFor="header-title" className="form-label">
                        Main Title
                        <span className="label-hint">Use \n for line breaks</span>
                    </label>
                    <textarea
                        id="header-title"
                        className="form-input"
                        rows={2}
                        value={data.title}
                        onChange={(e) => onChange({ title: e.target.value })}
                        placeholder="VIỆN PHẬT HỌC\nBỒ ĐỀ PHẬT QUỐC"
                    />
                </div>

                {/* Mobile Title Input */}
                <div className="form-group">
                    <label htmlFor="header-mobile-title" className="form-label">
                        Mobile Title
                    </label>
                    <textarea
                        id="header-mobile-title"
                        className="form-input"
                        rows={2}
                        value={data.mobileTitle}
                        onChange={(e) => onChange({ mobileTitle: e.target.value })}
                        placeholder="Về SBU"
                    />
                </div>

                {/* Subtitle Input */}


                {/* Background Image Workspace */}
                <ImageEditor
                    label="Desktop Background Image"
                    hint="Hero section background for desktop"
                    value={data.backgroundImage}
                    onChange={(val) => onChange({ backgroundImage: val })}
                    aspectRatio="landscape"
                />

                {/* Mobile Background Image Workspace */}
                <ImageEditor
                    label="Mobile Background Image"
                    hint="Hero section background for mobile"
                    value={data.mobileBackgroundImage}
                    onChange={(val) => onChange({ mobileBackgroundImage: val })}
                    aspectRatio="portrait"
                />
            </div>
        </div>
    )
}

export default HeaderEditor
