import React, { useEffect, useState } from 'react'
import './FooterEditor.css'
import SectionLockControl from './SectionLockControl'
import { useEmailTemplates } from '../ppm/forms/useEmailTemplates'

type EmailTemplateData = {
    locked?: boolean
    subject: string
    body: string
}

type EmailTemplateEditorProps = {
    data: EmailTemplateData
    onChange: (data: Partial<EmailTemplateData>) => void
}

type PreviewVariables = {
    [key: string]: string
}

const EmailTemplateEditor: React.FC<EmailTemplateEditorProps> = ({ data, onChange }) => {


     const { templates, loading, saveTemplate } = useEmailTemplates()



  
    const [activeTab, setActiveTab] = useState<'editor' | 'instructions' | 'variables'>('editor')

    const [previewVars, setPreviewVars] = useState<PreviewVariables>({
        name: 'John Doe',
        email: 'john@email.com',
        form_name: 'Sample Form',
        submission_date: new Date().toLocaleDateString()
    })

    const [currentTemplateId, setCurrentTemplateId] = useState<string | null>(null)
    const [isSaving, setIsSaving] = useState(false)
    const [saveStatus, setSaveStatus] = useState<'idle' | 'saved'>('idle')

    const safeData: EmailTemplateData = data || {
        subject: '',
        body: '',
        locked: false
    }

    // 🔥 LOAD TEMPLATE INTO EDITOR
    useEffect(() => {
        if (!loading && templates.length > 0) {
            const t = templates[0]

            setCurrentTemplateId(t.id)

            onChange({
                subject: t.subject,
                body: t.body
            })

            if (t.variables && Array.isArray(t.variables) && t.variables.length > 0) {
                const newVars: PreviewVariables = {}

                t.variables.forEach((v: any) => {
                    newVars[v.key] = v.desc || ''
                })

                setPreviewVars((prev) => ({
                    ...prev,
                    ...newVars
                }))
            }
        }
    }, [templates, loading])

    const renderPreview = () => {
        let rendered = safeData.body || ''

        Object.entries(previewVars).forEach(([key, value]) => {
            const regex = new RegExp(`{{\\s*${key}\\s*}}`, 'g')
            rendered = rendered.replace(regex, value)
        })

        return rendered || 'Your email preview will appear here...'
    }

    const handleSave = async () => {
        if (isSaving) return

        setIsSaving(true)
        setSaveStatus('idle')

        const variables = Object.entries(previewVars).map(([key, value]) => ({
            key,
            desc: value
        }))

        const result = await saveTemplate({
            id: currentTemplateId || undefined,
            template_name: 'submission_confirmation',
            subject: safeData.subject,
            body: safeData.body,
            variables
        })

        setIsSaving(false)

        if (result) {
            if (!currentTemplateId && Array.isArray(result) && result[0]?.id) {
                setCurrentTemplateId(result[0].id)
            }

            setSaveStatus('saved')
            setTimeout(() => {
                setSaveStatus('idle')
            }, 1500)
        }
    }

    return (
        <div className="footer-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Submission Email Template</h2>
                    <SectionLockControl
                        locked={safeData.locked}
                        onToggle={(newLocked) => onChange({ locked: newLocked })}
                    />
                </div>
                <p className="editor-subtitle">Customize transactional email content sent to users</p>
            </div>

            <div className="editor-tabs">
                <button
                    className={`tab-btn ${activeTab === 'editor' ? 'active' : ''}`}
                    onClick={() => setActiveTab('editor')}
                >
                    Editor
                </button>

                <button
                    className={`tab-btn ${activeTab === 'instructions' ? 'active' : ''}`}
                    onClick={() => setActiveTab('instructions')}
                >
                    Instructions
                </button>

                <button
                    className={`tab-btn ${activeTab === 'variables' ? 'active' : ''}`}
                    onClick={() => setActiveTab('variables')}
                >
                    Variables
                </button>
            </div>

            <div
                className={`editor-form ${safeData.locked ? 'locked-section' : ''}`}
                style={safeData.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}
            >
                {activeTab === 'editor' && (
                    <div className="tab-content fadeIn">
                        <div className="form-group">
                            <label className="form-label">Email Subject</label>
                            <input
                                type="text"
                                className="form-input"
                                value={safeData.subject}
                                onChange={(e) => onChange({ subject: e.target.value })}
                                placeholder="e.g. Welcome {{name}}"
                            />
                        </div>

                        <div className="form-group">
                            <label className="form-label">Email Body</label>
                            <textarea
                                className="form-input"
                                rows={10}
                                value={safeData.body}
                                onChange={(e) => onChange({ body: e.target.value })}
                                placeholder={`Write your email here...

Example:
Hello {{name}},

We received your submission.

Email: {{email}}
Date: {{submission_date}}

Thanks!`}
                            />
                        </div>

                        <div className="form-group">
                            <label className="form-label">Preview (Rendered)</label>
                            <div className="form-input" style={{ whiteSpace: 'pre-wrap', minHeight: 120 }}>
                                {renderPreview()}
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'instructions' && (
                    <div className="tab-content fadeIn">
                        <div className="form-group">
                            <label className="form-label">How Variables Work</label>

                            <div style={{ lineHeight: '1.6', fontSize: 14 }}>
                                <p>Use variables inside your email like this:</p>

                                <div style={{
                                    background: '#f5f5f5',
                                    padding: '12px',
                                    borderRadius: '6px',
                                    margin: '10px 0',
                                    fontFamily: 'monospace'
                                }}>
                                    Hello {'{{name}}'}
                                </div>

                                <p>They will be replaced automatically when the email is sent.</p>

                                <div style={{ marginTop: 12 }}>
                                    <strong>Available variables:</strong>
                                    <ul style={{ marginTop: 8, paddingLeft: 18 }}>
                                        {Object.keys(previewVars).map((key) => (
                                            <li key={key}><code>{`{{${key}}}`}</code> — Preview/test variable</li>
                                        ))}
                                    </ul>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'variables' && (
                    <div className="tab-content fadeIn">
                        <div className="form-group">
                            <label className="form-label">Preview Variables</label>

                            <div style={{
                                fontSize: 13,
                                marginBottom: 12,
                                color: '#666'
                            }}>
                                These values are for preview/demo purposes only. Actual emails will use real user-submitted data.
                            </div>

                            {Object.entries(previewVars).map(([key, value]) => (
                                <input
                                    key={key}
                                    className="form-input"
                                    value={value}
                                    onChange={(e) =>
                                        setPreviewVars(v => ({ ...v, [key]: e.target.value }))
                                    }
                                    placeholder={key}
                                />
                            ))}
                        </div>
                    </div>
                )}

                {/* 🔥 SAVE BUTTON */}
                <div style={{ marginTop: 20 }}>
                    <button
                        onClick={handleSave}
                        disabled={isSaving}
                        style={{
                            display: 'inline-flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            gap: 8,
                            padding: '10px 16px',
                            borderRadius: 8,
                            border: '1px solid #caa200',
                            background: isSaving ? '#f7d84d' : saveStatus === 'saved' ? '#e8f5e9' : '#facc15',
                            color: '#222',
                            fontWeight: 600,
                            cursor: isSaving ? 'not-allowed' : 'pointer',
                            opacity: isSaving ? 0.8 : 1,
                            textDecoration: 'none',
                            boxShadow: 'none',
                            outline: 'none',
                            borderBottom: '1px solid #caa200'
                        }}
                    >
                        {isSaving && (
                            <span
                                style={{
                                    width: 14,
                                    height: 14,
                                    border: '2px solid rgba(0,0,0,0.25)',
                                    borderTop: '2px solid rgba(0,0,0,0.75)',
                                    borderRadius: '50%',
                                    display: 'inline-block',
                                    animation: 'email-template-spin 0.8s linear infinite'
                                }}
                            />
                        )}
                        {isSaving ? 'Saving...' : saveStatus === 'saved' ? 'Saved' : 'Save Template'}
                    </button>

                    <style>
                        {`
                            @keyframes email-template-spin {
                                from { transform: rotate(0deg); }
                                to { transform: rotate(360deg); }
                            }
                        `}
                    </style>
                </div>
            </div>
        </div>
    )
}

export default EmailTemplateEditor