// src/components/ppm/forms/useExportSubmissionsCSV.ts

import { useState } from "react";
import { getSupabase } from "../../../database/supabase";


type Options = {
  pageSize?: number;
};

export const useExportSubmissionsCSV = (options: Options = {}) => {
  const pageSize = options.pageSize || 1000;

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const exportCSV = async () => {
    try {
      setLoading(true);
      setError(null);

      const supabase = await getSupabase();

      let allRows: any[] = [];
      let from = 0;
      let to = pageSize - 1;

      while (true) {
        const { data, error } = await supabase
          .from("form_submissions")
          .select("*")
          .range(from, to)
          .order("created_at", { ascending: false });

        if (error) throw error;
        if (!data || data.length === 0) break;

        allRows = [...allRows, ...data];

        if (data.length < pageSize) break;

        from += pageSize;
        to += pageSize;
      }

      // 🧠 collect dynamic keys
      const allKeys = new Set<string>();

      allRows.forEach((row) => {
        Object.keys(row.data || {}).forEach((k) => {
          if (k !== "email") allKeys.add(k);
        });
      });

      const dynamicKeys = Array.from(allKeys);

      // ❌ REMOVE id column
      const headers = [
        "form_id",
        "created_at",
        "email",
        ...dynamicKeys
      ];

      // 🧠 FORMAT DATE
      const formatDate = (iso: string) => {
        if (!iso) return "";
        const d = new Date(iso);
        const yyyy = d.getFullYear();
        const mm = String(d.getMonth() + 1).padStart(2, "0");
        const dd = String(d.getDate()).padStart(2, "0");
        const hh = String(d.getHours()).padStart(2, "0");
        const min = String(d.getMinutes()).padStart(2, "0");
        return `${yyyy}-${mm}-${dd} (${hh}:${min})`;
      };

      const csvRows = allRows.map((row) => {
        const base = {
          form_id: row.form_id,
          created_at: formatDate(row.created_at),
          email: row.data?.email || ""
        };

        const dynamic: any = {};

        dynamicKeys.forEach((key) => {
          dynamic[key] = row.data?.[key] ?? "";
        });

        return { ...base, ...dynamic };
      });

      // 🧼 HEADER FORMATTER (your ridiculous but valid rules)
      const formatHeader = (str: string) => {
        if (!str) return "";

        // (1) snake_case → space
        let s = str.replace(/_/g, " ");

        // (2) camelCase → split
        s = s.replace(/([a-z])([A-Z])/g, (_, a, b) => `${a} ${b.toLowerCase()}`);

        // (3) Title Case
        s = s
          .split(" ")
          .map((w) =>
            w ? w[0].toUpperCase() + w.slice(1).toLowerCase() : ""
          )
          .join(" ");

        return s;
      };

      const formattedHeaders = headers.map(formatHeader);

      const escapeCSV = (value: any) => {
        if (value === null || value === undefined) return "";
        const str = String(value);
        if (str.includes(",") || str.includes('"') || str.includes("\n")) {
          return `"${str.replace(/"/g, '""')}"`;
        }
        return str;
      };

      const csvString =
        formattedHeaders.join(",") +
        "\n" +
        csvRows
          .map((row) =>
            headers.map((h) => escapeCSV(row[h])).join(",")
          )
          .join("\n");

      const blob = new Blob([csvString], { type: "text/csv;charset=utf-8;" });
      const url = URL.createObjectURL(blob);

      const link = document.createElement("a");
      link.href = url;
      link.download = `form_submissions_${Date.now()}.csv`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

    } catch (err: any) {
      console.error(err);
      setError(err.message || "Export failed");
    } finally {
      setLoading(false);
    }
  };

  return {
    exportCSV,
    loading,
    error
  };
};