import React, { useState } from 'react'
import './ProgramsEditor.css'
import { ProgramsContent, ProgramItem, LectureItem, ProgramLink } from '../../contexts/types'
import ImageEditor from './ImageEditor'
import PopupDynamic from '../modals/PopupDynamic'
import SectionLockControl from './SectionLockControl'

type ProgramsEditorProps = {
    data: ProgramsContent
    onChange: (data: Partial<ProgramsContent>) => void
}

const ProgramsEditor: React.FC<ProgramsEditorProps> = ({ data, onChange }) => {
    const [editingProgramId, setEditingProgramId] = useState<string | null>(null)
    const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null)

    const updateProgram = (id: string, updates: Partial<ProgramItem>) => {
        const updatedItems = data.items.map(item =>
            item.id === id ? { ...item, ...updates } : item
        )
        onChange({ items: updatedItems })
    }

    const addProgram = () => {
        const newProgram: ProgramItem = {
            id: `prog-${Date.now()}`,
            title: 'New Program',
            description: 'Program description...',
            links: [{ label: 'New Link ›', href: '#' }],
            lectures: [],
            imageUrl: ''
        }
        onChange({ items: [...data.items, newProgram] })
        setEditingProgramId(newProgram.id)
    }

    const removeProgram = (id: string) => {
        const updatedItems = data.items.filter(item => item.id !== id)
        onChange({ items: updatedItems })
    }

    // Links Handlers
    const addLink = (progId: string) => {
        const program = data.items.find(p => p.id === progId)
        if (program) {
            updateProgram(progId, { links: [...program.links, { label: 'New Link ›', href: '#' }] })
        }
    }

    const updateLink = (progId: string, index: number, updates: Partial<ProgramLink>) => {
        const program = data.items.find(p => p.id === progId)
        if (program) {
            const newLinks = [...program.links]
            newLinks[index] = { ...newLinks[index], ...updates }
            updateProgram(progId, { links: newLinks })
        }
    }

    const removeLink = (progId: string, index: number) => {
        const program = data.items.find(p => p.id === progId)
        if (program) {
            const newLinks = program.links.filter((_, i) => i !== index)
            updateProgram(progId, { links: newLinks })
        }
    }

    // Lectures Handlers
    const addLecture = (progId: string) => {
        const program = data.items.find(p => p.id === progId)
        if (program) {
            const newLecture: LectureItem = {
                id: `lect-${Date.now()}`,
                title: 'New Lecture',
                subtitle: 'Lecture topic...',
                instructor: '',
                image: '',
                link: '#'
            }
            updateProgram(progId, { lectures: [...program.lectures, newLecture] })
        }
    }

    const updateLecture = (progId: string, lectId: string, updates: Partial<LectureItem>) => {
        const program = data.items.find(p => p.id === progId)
        if (program) {
            const newLectures = program.lectures.map(l =>
                l.id === lectId ? { ...l, ...updates } : l
            )
            updateProgram(progId, { lectures: newLectures })
        }
    }

    const removeLecture = (progId: string, lectId: string) => {
        const program = data.items.find(p => p.id === progId)
        if (program) {
            const newLectures = program.lectures.filter(l => l.id !== lectId)
            updateProgram(progId, { lectures: newLectures })
        }
    }

    return (
        <div className="programs-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Study Programs</h2>
                    <SectionLockControl locked={data.locked} onToggle={(locked) => onChange({ locked })} />
                </div>
                <p className="editor-subtitle">Manage curriculum blocks and new lectures</p>
            </div>

            <div className={`editor-form ${data.locked ? 'locked-section' : ''}`} style={data.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}>
                <div className="form-section">
                    <div className="section-header">
                        <h3 className="section-title">Course Blocks</h3>
                        <button className="btn-add-item" onClick={addProgram}>
                            + Add Program
                        </button>
                    </div>

                    <div className="programs-list">
                        {data.items.map((program, index) => (
                            <div key={program.id} className={`program-card ${editingProgramId === program.id ? 'active' : ''}`}>
                                <div className="program-card-header">
                                    <span className="item-label">{program.title}</span>
                                    <div className="item-actions">
                                        <button
                                            className="btn-action edit"
                                            onClick={() => setEditingProgramId(editingProgramId === program.id ? null : program.id)}
                                        >
                                            {editingProgramId === program.id ? 'Close' : 'Edit'}
                                        </button>
                                        <button
                                            className="btn-action delete"
                                            onClick={() => setDeleteConfirmId(program.id)}
                                        >
                                            Delete
                                        </button>
                                    </div>
                                </div>

                                {editingProgramId === program.id && (
                                    <div className="program-item-editor">
                                        <div className="form-group">
                                            <label className="form-label">Program Title</label>
                                            <input
                                                type="text"
                                                className="form-input"
                                                value={program.title}
                                                onChange={(e) => updateProgram(program.id, { title: e.target.value })}
                                            />
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label">Description</label>
                                            <textarea
                                                className="form-input"
                                                rows={2}
                                                value={program.description}
                                                onChange={(e) => updateProgram(program.id, { description: e.target.value })}
                                            />
                                        </div>

                                        <ImageEditor
                                            label="Banner Image"
                                            value={program.imageUrl}
                                            onChange={(url) => updateProgram(program.id, { imageUrl: url })}
                                            aspectRatio="landscape"
                                        />

                                        <div className="form-group" style={{ marginTop: '1rem' }}>
                                            <label className="form-label">Image Position (Desktop)</label>
                                            <div className="radio-group" style={{ display: 'flex', gap: '1.5rem' }}>
                                                <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', fontSize: '0.9rem' }}>
                                                    <input
                                                        type="radio"
                                                        name={`pos-${program.id}`}
                                                        checked={!program.imagePosition}
                                                        onChange={() => updateProgram(program.id, { imagePosition: undefined })}
                                                    />
                                                    Auto (Alternating)
                                                </label>
                                                <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', fontSize: '0.9rem' }}>
                                                    <input
                                                        type="radio"
                                                        name={`pos-${program.id}`}
                                                        checked={program.imagePosition === 'left'}
                                                        onChange={() => updateProgram(program.id, { imagePosition: 'left' })}
                                                    />
                                                    Image Left
                                                </label>
                                                <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', fontSize: '0.9rem' }}>
                                                    <input
                                                        type="radio"
                                                        name={`pos-${program.id}`}
                                                        checked={program.imagePosition === 'right'}
                                                        onChange={() => updateProgram(program.id, { imagePosition: 'right' })}
                                                    />
                                                    Image Right
                                                </label>
                                            </div>
                                        </div>

                                        {/* Links Editor */}
                                        <div className="sub-section">
                                            <div className="sub-section-header">
                                                <h4>Program Links</h4>
                                                <button className="btn-mini-add" onClick={() => addLink(program.id)}>+ Add Link</button>
                                            </div>
                                            <div className="links-editor-list">
                                                {program.links.map((link, idx) => (
                                                    <div key={idx} className="link-item-edit-row">
                                                        <div className="mini-item-row">
                                                            <input
                                                                type="text"
                                                                className="form-input mini"
                                                                placeholder="Link Label"
                                                                value={link.label}
                                                                onChange={(e) => updateLink(program.id, idx, { label: e.target.value })}
                                                            />
                                                            <input
                                                                type="text"
                                                                className="form-input mini"
                                                                placeholder="URL (e.g. /programs/2025)"
                                                                value={link.href}
                                                                onChange={(e) => updateLink(program.id, idx, { href: e.target.value })}
                                                            />
                                                            <button className="btn-mini-delete" onClick={() => removeLink(program.id, idx)} title="Delete Link">
                                                                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                                    <polyline points="3 6 5 6 21 6"></polyline>
                                                                    <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                                                </svg>
                                                            </button>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>

                                        {/* Lectures Editor */}
                                        <div className="sub-section">
                                            <div className="sub-section-header">
                                                <h4>Recent Lectures</h4>
                                                <button className="btn-mini-add" onClick={() => addLecture(program.id)}>+ Add Lecture</button>
                                            </div>
                                            <div className="lectures-editor-list">
                                                {program.lectures.map((lecture) => (
                                                    <div key={lecture.id} className="lecture-edit-card">
                                                        <div className="lecture-edit-grid">
                                                            <div className="lecture-edit-image">
                                                                <ImageEditor
                                                                    label="Thumb"
                                                                    value={lecture.image || ''}
                                                                    onChange={(url) => updateLecture(program.id, lecture.id, { image: url })}
                                                                    aspectRatio="square"
                                                                    compact={true}
                                                                />
                                                            </div>
                                                            <div className="lecture-edit-details">
                                                                <div className="mini-item-row">
                                                                    <input
                                                                        type="text"
                                                                        className="form-input mini"
                                                                        placeholder="Lecture Title"
                                                                        value={lecture.title}
                                                                        onChange={(e) => updateLecture(program.id, lecture.id, { title: e.target.value })}
                                                                    />
                                                                </div>
                                                                <div className="mini-item-row">
                                                                    <input
                                                                        type="text"
                                                                        className="form-input mini"
                                                                        placeholder="Subtitle"
                                                                        value={lecture.subtitle}
                                                                        onChange={(e) => updateLecture(program.id, lecture.id, { subtitle: e.target.value })}
                                                                    />
                                                                </div>
                                                                <div className="mini-item-row">
                                                                    <input
                                                                        type="text"
                                                                        className="form-input mini"
                                                                        placeholder="Destination Link"
                                                                        value={lecture.link || ''}
                                                                        onChange={(e) => updateLecture(program.id, lecture.id, { link: e.target.value })}
                                                                    />
                                                                    <button className="btn-mini-delete" onClick={() => removeLecture(program.id, lecture.id)} title="Delete Lecture">
                                                                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                                            <polyline points="3 6 5 6 21 6"></polyline>
                                                                            <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                                                                        </svg>
                                                                    </button>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            <PopupDynamic
                isOpen={!!deleteConfirmId}
                onClose={() => setDeleteConfirmId(null)}
                title="Delete Program?"
                subtitle={`Are you sure you want to delete "${data.items.find(p => p.id === deleteConfirmId)?.title}"? This action will remove all associated lectures and cannot be undone.`}
                type="error"
                buttons={[
                    {
                        buttonText: "Yes, Delete Program",
                        buttonTextActive: "Deleting...",
                        buttonTextResponse: "Deleted!",
                        variant: "danger",
                        onClick: async () => {
                            if (deleteConfirmId) {
                                removeProgram(deleteConfirmId);
                                setDeleteConfirmId(null);
                            }
                        }
                    },
                    {
                        buttonText: "Cancel",
                        variant: "secondary",
                        onClick: () => setDeleteConfirmId(null)
                    }
                ]}
            />
        </div>
    )
}

export default ProgramsEditor
