import React from 'react'
import './BanNhanSuEditor.css'
import { BanNhanSuContent, NhanSuGroup } from '../../contexts/types'
import ImageEditor from './ImageEditor'
import SectionLockControl from './SectionLockControl'

type BanNhanSuEditorProps = {
    data: BanNhanSuContent
    onChange: (data: Partial<BanNhanSuContent>) => void
}

const BanNhanSuEditor: React.FC<BanNhanSuEditorProps> = ({ data, onChange }) => {

    const handleGroupChange = (index: number, field: keyof NhanSuGroup, value: any) => {
        const newGroups = [...data.groups]
        newGroups[index] = { ...newGroups[index], [field]: value }
        onChange({ groups: newGroups })
    }

    const handleMemberChange = (groupIndex: number, memberIndex: number, value: string) => {
        const newGroups = [...data.groups]
        const newMembers = [...newGroups[groupIndex].members]
        newMembers[memberIndex] = value
        newGroups[groupIndex] = { ...newGroups[groupIndex], members: newMembers }
        onChange({ groups: newGroups })
    }

    const addMember = (groupIndex: number) => {
        const newGroups = [...data.groups]
        const newMembers = [...newGroups[groupIndex].members, '']
        newGroups[groupIndex] = { ...newGroups[groupIndex], members: newMembers }
        onChange({ groups: newGroups })
    }

    const removeMember = (groupIndex: number, memberIndex: number) => {
        const newGroups = [...data.groups]
        const newMembers = newGroups[groupIndex].members.filter((_, i) => i !== memberIndex)
        newGroups[groupIndex] = { ...newGroups[groupIndex], members: newMembers }
        onChange({ groups: newGroups })
    }

    return (
        <div className="nhan-su-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Ban Nhân Sự</h2>
                    <SectionLockControl locked={data.locked} onToggle={(locked) => onChange({ locked })} />
                </div>
                <p className="editor-subtitle">Update department groups and their members</p>
            </div>

            <div className={`editor-form ${data.locked ? 'locked-section' : ''}`} style={data.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}>
                {/* Desktop Background */}
                <div className="editor-section">
                    <div className="editor-section-title">Desktop Experience</div>
                    <ImageEditor
                        label="Main Desktop Background"
                        hint="Large background image shared by all groups on desktop"
                        value={data.desktopBackground}
                        onChange={(val) => onChange({ desktopBackground: val })}
                        aspectRatio="landscape"
                    />
                </div>

                {/* Groups Selection */}
                <div className="groups-list">
                    {data.groups.map((group, gIndex) => (
                        <div key={group.id} className="group-card">
                            <div className="group-card-header">
                                <h3 className="form-label" style={{ fontSize: '1.1rem', margin: 0 }}>
                                    {group.title}
                                </h3>
                            </div>

                            <div className="form-group">
                                <label className="form-label">Group Title</label>
                                <input
                                    type="text"
                                    className="form-input"
                                    value={group.title}
                                    onChange={(e) => handleGroupChange(gIndex, 'title', e.target.value)}
                                />
                            </div>

                            <ImageEditor
                                label="Mobile Header Background"
                                hint="Background image for this group's header on mobile"
                                value={group.mobileBackground}
                                onChange={(val) => handleGroupChange(gIndex, 'mobileBackground', val)}
                                aspectRatio="landscape"
                            />

                            <div className="form-group">
                                <label className="form-label">Members List</label>
                                <div className="members-list">
                                    {group.members.map((member, mIndex) => (
                                        <div key={mIndex} className="member-item">
                                            <input
                                                type="text"
                                                className="form-input"
                                                value={member}
                                                onChange={(e) => handleMemberChange(gIndex, mIndex, e.target.value)}
                                                placeholder="e.g. Giám viện: TT. Thích Huyền Châu"
                                            />
                                            <button
                                                className="btn-remove"
                                                onClick={() => removeMember(gIndex, mIndex)}
                                                title="Remove member"
                                            >
                                                &times;
                                            </button>
                                        </div>
                                    ))}
                                    <button className="btn-add" onClick={() => addMember(gIndex)}>
                                        + Add New Member
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    )
}

export default BanNhanSuEditor
