
import React, { useState } from 'react'
import './EducationEditor.css'
import { EducationContent, EducationItem } from '../../contexts/types'
import ImageEditor from './ImageEditor'
import PopupDynamic from '../modals/PopupDynamic'
import SectionLockControl from './SectionLockControl'
import RichTextEditor from './RichTextEditor'

type EducationEditorProps = {
    data: EducationContent
    onChange: (data: Partial<EducationContent>) => void
}

const EducationEditor: React.FC<EducationEditorProps> = ({ data, onChange }) => {
    const [editingItemId, setEditingItemId] = useState<string | null>(null)
    const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null)

    const updateItem = (id: string, updates: Partial<EducationItem>) => {
        const updatedItems = data.items.map(item => {
            if (item.id === id) {
                return { ...item, ...updates }
            }
            return item
        })
        onChange({ items: updatedItems })
    }

    const addItem = () => {
        const newItem: EducationItem = {
            id: `edu-${Date.now()}`,
            slug: `mon-hoc-${Date.now()}`,
            link: '#',
            title: 'Khóa học mới',
            category: 'Phật học',
            date: new Date().toLocaleDateString('vi-VN'),
            excerpt: 'Tóm tắt bài học...',
            body: '',
            image: '',
            isFeatured: false
        }
        onChange({ items: [newItem, ...data.items] })
        setEditingItemId(newItem.id)
    }

    const removeItem = (id: string) => {
        const updatedItems = data.items.filter(item => item.id !== id)
        onChange({ items: updatedItems })
    }

    return (
        <div className="edu-editor">
            <div className="editor-header-title">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h2>Edit Education Content</h2>
                    <SectionLockControl
                        locked={data.locked}
                        onToggle={(newLocked) => onChange({ locked: newLocked })}
                    />
                </div>
                <p className="editor-subtitle">Manage education items, courses and specialties</p>
            </div>

            <div className={`editor-form ${data.locked ? 'locked-section' : ''}`} style={data.locked ? { pointerEvents: 'none', opacity: 0.6 } : {}}>
                {/* Section Title */}
                <div className="form-section">
                    <div className="form-group">
                        <label htmlFor="section-title" className="form-label">
                            Section Title
                        </label>
                        <input
                            id="section-title"
                            type="text"
                            className="form-input"
                            value={data.sectionTitle}
                            onChange={(e) => onChange({ sectionTitle: e.target.value })}
                            placeholder="e.g., Các môn học Phật học"
                        />
                    </div>
                </div>

                {/* Education Items List */}
                <div className="form-section">
                    <div className="section-header">
                        <h3 className="section-title">Education Items</h3>
                        <button className="btn-add-item" onClick={addItem}>
                            + Add Education Item
                        </button>
                    </div>

                    <div className="edu-items-list">
                        {(data.items || []).map((item) => (
                            <div key={item.id} className={`edu-item-card ${editingItemId === item.id ? 'active' : ''}`}>
                                <div className="edu-item-header">
                                    <div className="edu-item-info">
                                        {item.isFeatured && <span className="featured-badge">Featured</span>}
                                        <span className="item-label">{item.title}</span>
                                    </div>
                                    <div className="item-actions">
                                        <button
                                            className="btn-action edit"
                                            onClick={() => setEditingItemId(editingItemId === item.id ? null : item.id)}
                                        >
                                            {editingItemId === item.id ? 'Close' : 'Edit'}
                                        </button>
                                        <button
                                            className="btn-action delete"
                                            onClick={() => setDeleteConfirmId(item.id)}
                                        >
                                            Delete
                                        </button>
                                    </div>
                                </div>

                                {editingItemId === item.id && (
                                    <div className="edu-item-editor">
                                        <div className="form-group">
                                            <label className="form-label">Title</label>
                                            <input
                                                type="text"
                                                className="form-input"
                                                value={item.title}
                                                onChange={(e) => updateItem(item.id, { title: e.target.value })}
                                            />
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label">Slug</label>
                                            <input
                                                type="text"
                                                className="form-input"
                                                value={item.slug}
                                                onChange={(e) => updateItem(item.id, { slug: e.target.value })}
                                            />
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label">Category</label>
                                            <input
                                                type="text"
                                                className="form-input"
                                                value={item.category}
                                                onChange={(e) => updateItem(item.id, { category: e.target.value })}
                                            />
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label">Date</label>
                                            <input
                                                type="text"
                                                className="form-input"
                                                value={item.date}
                                                onChange={(e) => updateItem(item.id, { date: e.target.value })}
                                            />
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label">Excerpt / Short Description</label>
                                            <textarea
                                                className="form-input"
                                                rows={3}
                                                value={item.excerpt}
                                                onChange={(e) => updateItem(item.id, { excerpt: e.target.value })}
                                            />
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label">Body Content</label>
                                            <RichTextEditor
                                                value={item.body}
                                                onChange={(val) => updateItem(item.id, { body: val })}
                                                placeholder="Enter course content..."
                                            />
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label">Link URL</label>
                                            <input
                                                type="text"
                                                className="form-input"
                                                value={item.link}
                                                onChange={(e) => updateItem(item.id, { link: e.target.value })}
                                            />
                                        </div>

                                        <ImageEditor
                                            label="Item Image"
                                            value={item.image}
                                            onChange={(url) => updateItem(item.id, { image: url })}
                                            aspectRatio="landscape"
                                        />

                                        <div className="news-toggle-group" style={{ marginTop: '10px' }}>
                                            <div className="news-toggle-label-side">
                                                <span className="news-toggle-title">Featured Content</span>
                                                <span className="news-toggle-label-hint">Highlight this item in the education list</span>
                                            </div>
                                            <label className="news-toggle-control">
                                                <input
                                                    type="checkbox"
                                                    checked={item.isFeatured}
                                                    onChange={(e) => updateItem(item.id, { isFeatured: e.target.checked })}
                                                />
                                                <span className="news-toggle-slider"></span>
                                            </label>
                                        </div>
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            <PopupDynamic
                isOpen={!!deleteConfirmId}
                onClose={() => setDeleteConfirmId(null)}
                title="Delete Education Item?"
                subtitle={`Are you sure you want to delete and unpublish this content?`}
                type="error"
                buttons={[
                    {
                        buttonText: "Yes, Delete",
                        variant: "danger",
                        onClick: async () => {
                            if (deleteConfirmId) {
                                removeItem(deleteConfirmId);
                                setDeleteConfirmId(null);
                            }
                        }
                    },
                    {
                        buttonText: "Cancel",
                        variant: "secondary",
                        onClick: () => setDeleteConfirmId(null)
                    }
                ]}
            />
        </div>
    )
}

export default EducationEditor
