// Replaces {{token}} in a string using actual sample values entered by the user
const resolvePreview = (
  template: string,
  tokenMap: Record<string, string>,
  sampleValues: Record<string, string>,
  draftFormId?: string
): string => {

  // Format: DD/MM/YYYY at HH:MM AM/PM
  const now = new Date();

  const pad = (n: number) => n.toString().padStart(2, '0');

  let hours = now.getHours();
  const minutes = pad(now.getMinutes());
  const ampm = hours >= 12 ? 'PM' : 'AM';
  hours = hours % 12 || 12;

  const formattedDate =
    `${pad(now.getDate())}/${pad(now.getMonth() + 1)}/${now.getFullYear()} at ${pad(hours)}:${minutes} ${ampm}`;

  const tokenToSample: Record<string, string> = {};

  Object.entries(tokenMap).forEach(([fieldId, token]) => {
    tokenToSample[token] = sampleValues[fieldId] || `{{${token}}}`;
  });

  return template.replace(/\{\{([^}]+)\}\}/g, (_, key) => {
    const trimmed = key.trim();

    // ✅ SPECIAL TOKENS
    if (trimmed === 'submission_date') return formattedDate;
    if (trimmed === 'form_name') return draftFormId || '';

    return tokenToSample[trimmed] !== undefined
      ? tokenToSample[trimmed]
      : `{{${trimmed}}}`;
  });
};

